.runAll(\"cancel\")\n    }\n\n    complete() {\n        this.runAll(\"complete\")\n    }\n}\n\nfunction getMax(\n    animations: GroupedAnimations,\n    propName: \"iterationDuration\" | \"duration\"\n): number {\n    let max = 0\n\n    for (let i = 0; i < animations.length; i++) {\n        const value = animations[i][propName]\n        if (value !== null && value > max) {\n            max = value\n        }\n    }\n    return max\n}\n","import { GroupAnimation } from \"./GroupAnimation\"\nimport { AnimationPlaybackControlsWithThen } from \"./types\"\n\nexport class GroupAnimationWithThen\n    extends GroupAnimation\n    implements AnimationPlaybackControlsWithThen\n{\n    then(onResolve: VoidFunction, _onReject?: VoidFunction) {\n        return this.finished.finally(onResolve).then(() => {})\n    }\n}\n","import { NativeAnimation } from \"./NativeAnimation\"\nimport { AnyResolvedKeyframe } from \"./types\"\n\nexport class NativeAnimationWrapper<\n    T extends AnyResolvedKeyframe\n> extends NativeAnimation<T> {\n    constructor(animation: Animation) {\n        super()\n\n        this.animation = animation\n        animation.onfinish = () => {\n            this.finishedTime = this.time\n            this.notifyFinished()\n        }\n    }\n}\n","import { NativeAnimation } from \"../NativeAnimation\"\nimport { AnyResolvedKeyframe } from \"../types\"\n\nconst animationMaps = new WeakMap<\n    Element,\n    Map<string, NativeAnimation<AnyResolvedKeyframe>>\n>()\nexport const animationMapKey = (name: string, pseudoElement: string = \"\") =>\n    `${name}:${pseudoElement}`\n\nexport function getAnimationMap(element: Element) {\n    let map = animationMaps.get(element)\n    if (!map) {\n        map = new Map()\n        animationMaps.set(element, map)\n    }\n    return map\n}\n","import type { DynamicOption } from \"../types\"\nimport type { VisualElement } from \"../../render/VisualElement\"\n\nexport function calcChildStagger(\n    children: Set<VisualElement>,\n    chil