SelectorEffect<T>(\n    subjectEffect: (\n        subject: T,\n        values: Record<string, MotionValue>\n    ) => VoidFunction\n) {\n    return (\n        subject: ElementOrSelector,\n        values: Record<string, MotionValue>\n    ) => {\n        const elements = resolveElements(subject)\n        const subscriptions: VoidFunction[] = []\n\n        for (const element of elements) {\n            const remove = subjectEffect(element as T, values)\n            subscriptions.push(remove)\n        }\n\n        return () => {\n            for (const remove of subscriptions) remove()\n        }\n    }\n}\n","import { ValueType } from \"../types\"\n\n/**\n * Provided a value and a ValueType, returns the value as that value type.\n */\nexport const getValueAsType = (value: any, type?: ValueType) => {\n    return type && typeof value === \"number\"\n        ? (type as any).transform(value)\n        : value\n}\n","import { AnyResolvedKeyframe } from \"../animation/types\"\nimport { cancelFrame, frame } from \"../frameloop/frame\"\nimport { MotionValue } from \"../value\"\nimport { numberValueTypes } from \"../value/types/maps/number\"\nimport { getValueAsType } from \"../value/types/utils/get-as-type\"\n\nexport class MotionValueState {\n    latest: { [name: string]: AnyResolvedKeyframe } = {}\n\n    private values = new Map<\n        string,\n        { value: MotionValue; onRemove: VoidFunction }\n    >()\n\n    set(\n        name: string,\n        value: MotionValue,\n        render?: VoidFunction,\n        computed?: MotionValue,\n        useDefaultValueType = true\n    ) {\n        const existingValue = this.values.get(name)\n\n        if (existingValue) {\n            existingValue.onRemove()\n        }\n\n        const onChange = () => {\n            const v = value.get()\n\n            if (useDefaultValueType) {\n                this.latest[name] = getValueAsType(v, numberValueTypes[name])\n            } else {\n                this.latest[name] = v\n            }\n