     upEvent,\n                (target as any) === window ||\n                    (target as any) === document ||\n                    options.useGlobalTarget ||\n                    isNodeOrChild(target, upEvent.target as Element)\n            )\n        }\n\n        const onPointerCancel = (cancelEvent: PointerEvent) => {\n            onPointerEnd(cancelEvent, false)\n        }\n\n        window.addEventListener(\"pointerup\", onPointerUp, endEventOptions)\n        window.addEventListener(\n            \"pointercancel\",\n            onPointerCancel,\n            endEventOptions\n        )\n    }\n\n    targets.forEach((target: EventTarget) => {\n        const pointerDownTarget = options.useGlobalTarget ? window : target\n        pointerDownTarget.addEventListener(\n            \"pointerdown\",\n            startPress as EventListener,\n            eventOptions\n        )\n\n        if (isHTMLElement(target)) {\n            target.addEventListener(\"focus\", (event) =>\n                enableKeyboardPress(event as FocusEvent, eventOptions)\n            )\n\n            if (\n                !isElementKeyboardAccessible(target) &&\n                !target.hasAttribute(\"tabindex\")\n            ) {\n                target.tabIndex = 0\n            }\n        }\n    })\n\n    return cancelEvents\n}\n","import { isCSSVar } from \"./is-css-var\"\n\nexport function getComputedStyle(\n    element: HTMLElement | SVGElement,\n    name: string\n) {\n    const computedStyle = window.getComputedStyle(element)\n    return isCSSVar(name)\n        ? computedStyle.getPropertyValue(name)\n        : computedStyle[name as any]\n}\n","import { isObject } from \"motion-utils\"\n\n/**\n * Checks if an element is an SVG element in a way\n * that works across iframes\n */\nexport function isSVGElement(element: unknown): element is SVGElement {\n    return isObject(element) && \"ownerSVGElement\" in element\n}\n","import { isSVGElement } from \"../utils/is-svg-element\"\nimport { ElementOrSelector, resolveElements } from \"../utils/resolve-elements\"\nimport { ResizeHandler } from \"./types\"\n\nconst resizeHandlers = new WeakMap<Element, Set<ResizeHandler<Element>>>()\n\nlet observer: ResizeObserver | undefined\n\nconst getSize =\n    (\n        borderBoxAxis: \"inline\" | \"block\",\n        svgAxis: \"width\" | \"height\",\n        htmlAxis: \"offsetWidth\" | \"offsetHeight\"\n    ) =>\n    (target: Element, borderBoxSize?: ReadonlyArray<ResizeObserverSize>) => {\n        if (borderBoxSize && borderBoxSize[0]) {\n            return borderBoxSize[0][\n                (borderBoxAxis + \"Size\") as keyof ResizeObserverSize\n            ]\n        } else if (isSVGElement(target) && \"getBBox\" in target) {\n            return (target as SVGGraphicsElement).getBBox()[svgAxis]\n        } else {\n            return (target as HTMLElement)[htmlAxis]\n        }\n    }\n\nconst getWidth = /*@__PURE__*/ getSize(\"inline\", \"width\", \"offsetWidth\")\nconst getHeight = /*@__PURE__*/ getSize(\"block\", \"height\", \"offsetHeight\")\n\nfunction notifyTarget({ target, borderBoxSize }: ResizeObserverEntry) {\n    resizeHandlers.get(target)?.forEach((handler) => {\n        handler(target, {\n            get width() {\n                return getWidth(target, borderBoxSize)\n            },\n            get height() {\n                return getHeight(target, borderBoxSize)\n            },\n        })\n    })\n}\n\nfunction notifyAll(entries: ResizeObserverEntry[]) {\n    entries.forEach(notifyTarget)\n}\n\nfunction createResizeObserver() {\n    if (typeof ResizeObserver === \"undefined\") return\n\n    observer = new ResizeObserver(notifyAll)\n}\n\nexport function resizeElement(\n    target: ElementOrSelector,\n    handler: ResizeHandler<Element>\n) {\n    if (!observer) createResizeObserver()\n\n    const elements = resolveElements(target)\n\n    elements.forEach((element) => {\n        let elementHandlers = resizeHandlers.get(element)\n\n        if (!elementHandlers) {\n            elementHandlers = new Set()\n            resizeHandlers.set(element, elementHandlers)\n        }\n\n        elementHandlers.add(handler)\n        observer?.observe(element)\n    })\n\n    return () => {\n        elements.forEach((element) => {\n            const elementHandlers = resizeHandlers.get(element)\n\n            elementHandlers?.delete(handler)\n\n            if (!elementHandlers?.size) {\n                observer?.unobserve(element)\n            }\n        })\n    }\n}\n","import { WindowResizeHandler } from \"./types\"\n\nconst windowCallbacks = new Set<WindowResizeHandler>()\n\nlet windowResizeHandler: VoidFunction | undefined\n\nfunction createWindowResizeHandler() {\n    windowResizeHandler = () => {\n        const info = {\n            get width() {\n                return window.innerWidth\n            },\n            get height() {\n                return window.innerHeight\n            },\n        }\n\n        windowCallbacks.forEach((callback) => callback(info))\n    }\n\n    window.addEventListener(\"resize\", windowResizeHandler)\n}\n\nexport function resizeWindow(callback: WindowResizeHandler) {\n    windowCallbacks.add(callback)\n\n    if (!windowResizeHandler) createWindowResizeHandler()\n\n    return () => {\n        windowCallbacks.delete(callback)\n\n        if (\n            !windowCallbacks.size &&\n            typeof windowResizeHandler === \"function\"\n        ) {\n            window.removeEventListener(\"resize\", windowResizeHandler)\n            windowResizeHandler = undefined\n        }\n    }\n}\n","import { ElementOrSelector } from \"../utils/resolve-elements\"\nimport { resizeElement } from \"./handle-element\"\nimport { resizeWindow } from \"./handle-window\"\nimport { ResizeHandler, WindowResizeHandler } from \"./types\"\n\nexport function resize(onResize: WindowResizeHandler): VoidFunction\nexport function resize(\n    target: ElementOrSelector,\n    onResize: ResizeHandler<Element>\n): VoidFunction\nexport function resize(\n    a: WindowResizeHandler | ElementOrSelector,\n    b?: ResizeHandler<Element>\n) {\n    return typeof a === \"function\" ? resizeWindow(a) : resizeElement(a, b!)\n}\n","import { ProgressTimeline } from \"../animation/types\"\nimport { cancelFrame, frame } from \"../frameloop\"\n\ntype Update = (progress: number) => void\n\nexport function observeTimeline(update: Update, timeline: ProgressTimeline) {\n    let prevProgress: number\n\n    const onFrame = () => {\n        const { currentTime } = timeline\n        const percentage = currentTime === null ? 0 : currentTime.value\n        const progress = percentage / 100\n\n        if (prevProgress !== progress) {\n            update(progress)\n        }\n\n        prevProgress = progress\n    }\n\n    frame.preUpdate(onFrame, true)\n\n    return () => cancelFrame(onFrame)\n}\n","import type { LayoutProjectionMetrics, StatsRecording } from \"./types\"\n\nexport type InactiveStatsBuffer = {\n    value: null\n    addProjectionMetrics: null\n}\n\nexport type ActiveStatsBuffer = {\n    value: StatsRecording\n    addProjectionMetrics: (metrics: LayoutProjectionMetrics) => void\n}\n\nexport const statsBuffer: InactiveStatsBuffer | ActiveStatsBuffer = {\n    value: null,\n    addProjectionMetrics: null,\n}\n","import { ActiveStatsBuffer, statsBuffer } from \"./buffer\"\n\nfunction clearStatsBuffer() {\n    statsBuffer.value = null\n    statsBuffer.addProjectionMetrics = null\n}\n\nexport function recordStats() {\n    if (statsBuffer.value) {\n        clearStatsBuffer()\n        throw new Error(\"Stats are already being measured\")\n    }\n\n    const buffer = statsBuffer as unknown as ActiveStatsBuffer\n\n    buffer.value = {\n        layoutProjection: {\n            nodes: [],\n            calculatedTargetDeltas: [],\n            calculatedProjections: [],\n        },\n    }\n\n    buffer.addProjectionMetrics = (metrics) => {\n        const { layoutProjection } = buffer.value\n        layoutProjection.nodes.push(metrics.nodes)\n        layoutProjection.calculatedTargetDeltas.push(\n            metrics.calculatedTargetDeltas\n        )\n        layoutProjection.calculatedProjections.push(\n            metrics.calculatedProjections\n        )\n    }\n}\n","import { isSVGElement } from \"./is-svg-element\"\n\n/**\n * Checks if an element is specifically an SVGSVGElement (the root SVG element)\n * in a way that works across iframes\n */\nexport function isSVGSVGElement(element: unknown): element is SVGSVGElement {\n    return isSVGElement(element) && element.tagName === \"svg\"\n}\n","import { Easing, easingDefinitionToFunction } from \"motion-utils\"\nimport { DynamicOption } from \"../animation/types\"\n\nexport type StaggerOrigin = \"first\" | \"last\" | \"center\" | number\n\nexport type StaggerOptions = {\n    startDelay?: number\n    from?: StaggerOrigin\n    ease?: Easing\n}\n\nexport function getOriginIndex(from: StaggerOrigin, total: number) {\n    if (from === \"first\") {\n        return 0\n    } else {\n        const lastIndex = total - 1\n        return from === \"last\" ? lastIndex : lastIndex / 2\n    }\n}\n\nexport function stagger(\n    duration: number = 0.1,\n    { startDelay = 0, from = 0, ease }: StaggerOptions = {}\n): DynamicOption<number> {\n    return (i: number, total: number) => {\n        const fromIndex =\n            typeof from === \"number\" ? from : getOriginIndex(from, total)\n        const distance = Math.abs(fromIndex - i)\n        let delay = duration * distance\n\n        if (ease) {\n            const maxDelay = total * duration\n            const easingFunction = easingDefinitionToFunction(ease)\n            delay = easingFunction(delay / maxDelay) * maxDelay\n        }\n\n        return startDelay + delay\n    }\n}\n","import { EasingFunction } from \"motion-utils\"\nimport { interpolate } from \"./interpolate\"\n\n/**\n * @public\n */\nexport interface TransformOptions<T> {\n    /**\n     * Clamp values to within the given range. Defaults to `true`\n     *\n     * @public\n     */\n    clamp?: boolean\n\n    /**\n     * Easing functions to use on the interpolations between each value in the input and output ranges.\n     *\n     * If provided as an array, the array must be one item shorter than the input and output ranges, as the easings apply to the transition **between** each.\n     *\n     * @public\n     */\n    ease?: EasingFunction | EasingFunction[]\n\n    /**\n     * Provide a function that can interpolate between any two values in the provided range.\n     *\n     * @public\n     */\n    mixer?: (from: T, to: T) => (v: number) => any\n}\n\n/**\n * Transforms numbers into other values by mapping them from an input range to an output range.\n * Returns the type of the input provided.\n *\n * @remarks\n *\n * Given an input range of `[0, 200]` and an output range of\n * `[0, 1]`, this function will return a value between `0` and `1`.\n * The input range must be a linear series of numbers. The output range\n * can be any supported value type, such as numbers, colors, shadows, arrays, objects and more.\n * Every value in the output range must be of the same type and in the same format.\n *\n * ```jsx\n * export function MyComponent() {\n *    const inputRange = [0, 200]\n *    const outputRange = [0, 1]\n *    const output = transform(100, inputRange, outputRange)\n *\n *    // Returns 0.5\n *    return <div>{output}</div>\n * }\n * ```\n *\n * @param inputValue - A number to transform between the input and output ranges.\n * @param inputRange - A linear series of numbers (either all increasing or decreasing).\n * @param outputRange - A series of numbers, colors, strings, or arrays/objects of those. Must be the same length as `inputRange`.\n * @param options - Clamp: Clamp values to within the given range. Defaults to `true`.\n *\n * @public\n */\nexport function transform<T>(\n    inputValue: number,\n    inputRange: number[],\n    outputRange: T[],\n    options?: TransformOptions<T>\n): T\n/**\n *\n * Transforms numbers into other values by mapping them from an input range to an output range.\n *\n * Given an input range of `[0, 200]` and an output range of\n * `[0, 1]`, this function will return a value between `0` and `1`.\n * The input range must be a linear series of numbers. The output range\n * can be any supported value type, such as numbers, colors, shadows, arrays, objects and more.\n * Every value in the output range must be of the same type and in the same format.\n *\n * ```jsx\n * export function MyComponent() {\n *     const inputRange = [-200, -100, 100, 200]\n *     const outputRange = [0, 1, 1, 0]\n *     const convertRange = transform(inputRange, outputRange)\n *     const output = convertRange(-150)\n *\n *     // Returns 0.5\n *     return <div>{output}</div>\n * }\n *\n * ```\n *\n * @param inputRange - A linear series of numbers (either all increasing or decreasing).\n * @param outputRange - A series of numbers, colors or strings. Must be the same length as `inputRange`.\n * @param options - Clamp: clamp values to within the given range. Defaults to `true`.\n *\n * @public\n */\nexport function transform<T>(\n    inputRange: number[],\n    outputRange: T[],\n    options?: TransformOptions<T>\n): (inputValue: number) => T\nexport function transform<T>(\n    ...args:\n        | [number, number[], T[], TransformOptions<T>?]\n        | [number[], T[], TransformOptions<T>?]\n) {\n    const useImmediate = !Array.isArray(args[0])\n    const argOffset = useImmediate ? 0 : -1\n    const inputValue = args[0 + argOffset] as number\n    const inputRange = args[1 + argOffset] as number[]\n    const outputRange = args[2 + argOffset] as T[]\n    const options = args[3 + argOffset] as TransformOptions<T>\n\n    const interpolator = interpolate(inputRange, outputRange, options)\n\n    return useImmediate ? interpolator(inputValue) : interpolator\n}\n","import { MotionValue, motionValue } from \".\"\nimport { JSAnimation } from \"../animation/JSAnimation\"\nimport { AnyResolvedKeyframe, ValueAnimationTransition } from \"../animation/types\"\nimport { frame } from \"../frameloop\"\nimport { isMotionValue } from \"./utils/is-motion-value\"\n\n/**\n * Options for useFollowValue hook, extending ValueAnimationTransition\n * but excluding lifecycle callbacks that don't make sense for the hook pattern.\n */\nexport type FollowValueOptions = Omit<\n    ValueAnimationTransition,\n    \"onUpdate\" | \"onComplete\" | \"onPlay\" | \"onRepeat\" | \"onStop\"\n> & {\n    /**\n     * When true, the first change from a tracked `MotionValue` source\n     * will jump to the new value instead of animating. Subsequent\n     * changes animate normally. This prevents unwanted animations\n     * on page refresh or back navigation (e.g. `useScroll` + `useSpring`).\n     *\n     * @default false\n     */\n    skipInitialAnimation?: boolean\n}\n\n/**\n * Create a `MotionValue` that animates to its latest value using any transition type.\n * Can either be a value or track another `MotionValue`.\n *\n * ```jsx\n * const x = motionValue(0)\n * const y = followValue(x, { type: \"spring\", stiffness: 300 })\n * // or with tween\n * const z = followValue(x, { type: \"tween\", duration: 0.5, ease: \"easeOut\" })\n * ```\n *\n * @param source - Initial value or MotionValue to track\n * @param options - Animation transition options\n * @returns `MotionValue`\n *\n * @public\n */\nexport function followValue<T extends AnyResolvedKeyframe>(\n    source: T | MotionValue<T>,\n    options?: FollowValueOptions\n) {\n    const initialValue = isMotionValue(source) ? source.get() : source\n    const value = motionValue(initialValue)\n\n    attachFollow(value, source, options)\n\n    return value\n}\n\n/**\n * Attach an animation to a MotionValue that will animate whenever the value changes.\n * Similar to attachSpring but supports any transition type (spring, tween, inertia, etc.)\n *\n * @param value - The MotionValue to animate\n * @param source - Initial value or MotionValue to track\n * @param options - Animation transition options\n * @returns Cleanup function\n *\n * @public\n */\nexport function attachFollow<T extends AnyResolvedKeyframe>(\n    value: MotionValue<T>,\n    source: T | MotionValue<T>,\n    options: FollowValueOptions = {}\n): VoidFunction {\n    const initialValue = value.get()\n\n    let activeAnimation: JSAnimation<number> | null = null\n    let latestValue = initialValue\n    let latestSetter: (v: T) => void\n\n    const unit =\n        typeof initialValue === \"string\"\n            ? initialValue.replace(/[\\d.-]/g, \"\")\n            : undefined\n\n    const stopAnimation = () => {\n        if (activeAnimation) {\n            activeAnimation.stop()\n            activeAnimation = null\n        }\n        value.animation = undefined\n    }\n\n    const startAnimation = () => {\n        const currentValue = asNumber(value.get())\n        const targetValue = asNumber(latestValue)\n\n        // Don't animate if we're already at the target\n        if (currentValue === targetValue) {\n            stopAnimation()\n            return\n        }\n\n        // Use the running animation's analytical velocity for accuracy,\n        // falling back to the MotionValue's velocity for the initial animation.\n        // This prevents systematic velocity loss at high frame rates (240hz+).\n        const velocity = activeAnimation\n            ? activeAnimation.getGeneratorVelocity()\n            : value.getVelocity()\n\n        stopAnimation()\n\n        activeAnimation = new JSAnimation({\n            keyframes: [currentValue, targetValue],\n            velocity,\n            // Default to spring if no type specified (matches useSpring behavior)\n            type: \"spring\",\n            restDelta: 0.001,\n            restSpeed: 0.01,\n            ...options,\n            onUpdate: latestSetter,\n        })\n    }\n\n    // Use a stable function reference so the frame loop Set deduplicates\n    // multiple calls within the same frame (e.g. rapid mouse events)\n    const scheduleAnimation = () => {\n        startAnimation()\n        value.animation = activeAnimation ?? undefined\n        value[\"events\"].animationStart?.notify()\n        activeAnimation?.then(() => {\n            value.animation = undefined\n            value[\"events\"].animationComplete?.notify()\n        })\n    }\n\n    value.attach((v, set) => {\n        latestValue = v\n        latestSetter = (latest) => set(parseValue(latest, unit) as T)\n        frame.postRender(scheduleAnimation)\n    }, stopAnimation)\n\n    if (isMotionValue(source)) {\n        let skipNextAnimation = options.skipInitialAnimation === true\n\n        const removeSourceOnChange = source.on(\"change\", (v) => {\n            if (skipNextAnimation) {\n                skipNextAnimation = false\n                value.jump(parseValue(v, unit) as T, false)\n            } else {\n                value.set(parseValue(v, unit) as T)\n            }\n        })\n\n        const removeValueOnDestroy = value.on(\"destroy\", removeSourceOnChange)\n\n        return () => {\n            removeSourceOnChange()\n            removeValueOnDestroy()\n        }\n    }\n\n    return stopAnimation\n}\n\nfunction parseValue(v: AnyResolvedKeyframe, unit?: string) {\n    return unit ? v + unit : v\n}\n\nfunction asNumber(v: AnyResolvedKeyframe) {\n    return typeof v === \"number\" ? v : parseFloat(v)\n}\n","import { MotionValue } from \".\"\nimport { cancelFrame, frame } from \"../frameloop\"\n\nexport function subscribeValue<O>(\n    inputValues: MotionValue[],\n    outputValue: MotionValue<O>,\n    getLatest: () => O\n) {\n    const update = () => outputValue.set(getLatest())\n    const scheduleUpdate = () => frame.preRender(update, false, true)\n\n    const subscriptions = inputValues.map((v) => v.on(\"change\", scheduleUpdate))\n\n    outputValue.on(\"destroy\", () => {\n        subscriptions.forEach((unsubscribe) => unsubscribe())\n        cancelFrame(update)\n    })\n}\n","import { MotionValue, collectMotionValues, motionValue } from \".\"\nimport { subscribeValue } from \"./subscribe-value\"\n\nexport type TransformInputRange = number[]\nexport type SingleTransformer<I, O> = (input: I) => O\nexport type MultiTransformer<I, O> = (input: I[]) => O\nexport type ValueTransformer<I, O> =\n    | SingleTransformer<I, O>\n    | MultiTransformer<I, O>\n\n/**\n * Create a `MotionValue` that transforms the output of other `MotionValue`s by\n * passing their latest values through a transform function.\n *\n * Whenever a `MotionValue` referred to in the provided function is updated,\n * it will be re-evaluated.\n *\n * ```jsx\n * const x = motionValue(0)\n * const y = transformValue(() => x.get() * 2) // double x\n * ```\n *\n * @param transformer - A transform function. This function must be pure with no side-effects or conditional statements.\n * @returns `MotionValue`\n *\n * @public\n */\nexport function transformValue<O>(transform: () => O): MotionValue<O> {\n    const collectedValues: MotionValue[] = []\n\n    /**\n     * Open session of collectMotionValues. Any MotionValue that calls get()\n     * inside transform will be saved into this array.\n     */\n    collectMotionValues.current = collectedValues\n    const initialValue = transform()\n    collectMotionValues.current = undefined\n\n    const value = motionValue(initialValue)\n\n    subscribeValue(collectedValues, value, transform)\n\n    return value\n}\n","import { MotionValue } from \".\"\nimport { transform, TransformOptions } from \"../utils/transform\"\nimport { transformValue } from \"./transform-value\"\n\nexport type MapInputRange = number[]\n\n/**\n * Create a `MotionValue` that maps the output of another `MotionValue` by\n * mapping it from one range of values into another.\n *\n * @remarks\n *\n * Given an input range of `[-200, -100, 100, 200]` and an output range of\n * `[0, 1, 1, 0]`, the returned `MotionValue` will:\n *\n * - When provided a value between `-200` and `-100`, will return a value between `0` and  `1`.\n * - When provided a value between `-100` and `100`, will return `1`.\n * - When provided a value between `100` and `200`, will return a value between `1` and  `0`\n *\n * The input range must be a linear series of numbers. The output range\n * can be any value type supported by Motion: numbers, colors, shadows, etc.\n *\n * Every value in the output range must be of the same type and in the same format.\n *\n * ```jsx\n * const x = motionValue(0)\n * const xRange = [-200, -100, 100, 200]\n * const opacityRange = [0, 1, 1, 0]\n * const opacity = mapValue(x, xRange, opacityRange)\n * ```\n *\n * @param inputValue - `MotionValue`\n * @param inputRange - A linear series of numbers (either all increasing or decreasing)\n * @param outputRange - A series of numbers, colors or strings. Must be the same length as `inputRange`.\n * @param options -\n *\n *  - clamp: boolean. Clamp values to within the given range. Defaults to `true`\n *  - ease: EasingFunction[]. Easing functions to use on the interpolations between each value in the input and output ranges. If provided as an array, the array must be one item shorter than the input and output ranges, as the easings apply to the transition between each.\n *\n * @returns `MotionValue`\n *\n * @public\n */\nexport function mapValue<O>(\n    inputValue: MotionValue<number>,\n    inputRange: MapInputRange,\n    outputRange: O[],\n    options?: TransformOptions<O>\n): MotionValue<O> {\n    const map = transform(inputRange, outputRange, options)\n    return transformValue(() => map(inputValue.get()))\n}\n","import { MotionValue } from \".\"\nimport { AnyResolvedKeyframe, SpringOptions } from \"../animation/types\"\nimport { attachFollow, followValue } from \"./follow-value\"\n\n/**\n * Create a `MotionValue` that animates to its latest value using a spring.\n * Can either be a value or track another `MotionValue`.\n *\n * ```jsx\n * const x = motionValue(0)\n * const y = springValue(x, { stiffness: 300 })\n * ```\n *\n * @param source - Initial value or MotionValue to track\n * @param options - Spring configuration options\n * @returns `MotionValue`\n *\n * @public\n */\nexport function springValue<T extends AnyResolvedKeyframe>(\n    source: T | MotionValue<T>,\n    options?: SpringOptions\n) {\n    return followValue(source, { type: \"spring\", ...options })\n}\n\n/**\n * Attach a spring animation to a MotionValue that will animate whenever the value changes.\n *\n * @param value - The MotionValue to animate\n * @param source - Initial value or MotionValue to track\n * @param options - Spring configuration options\n * @returns Cleanup function\n *\n * @public\n */\nexport function attachSpring<T extends AnyResolvedKeyframe>(\n    value: MotionValue<T>,\n    source: T | MotionValue<T>,\n    options?: SpringOptions\n): VoidFunction {\n    return attachFollow(value, source, { type: \"spring\", ...options })\n}\n","import { color } from \"../color\"\nimport { complex } from \"../complex\"\nimport { dimensionValueTypes } from \"../dimensions\"\nimport { testValueType } from \"../test\"\n\n/**\n * A list of all ValueTypes\n */\nconst valueTypes = [...dimensionValueTypes, color, complex]\n\n/**\n * Tests a value against the list of ValueTypes\n */\nexport const findValueType = (v: any) => valueTypes.find(testValueType(v))\n","import { ElementOrSelector, resolveElements } from \"../../utils/resolve-elements\"\n\nlet nameCount = 0\n\n/**\n * Generated names live in their own namespace so we can tell a name we own\n * (and must clean up) from an author-defined one - and so a stale generated\n * name left behind by an interrupted transition is re-owned, not mistaken for\n * the author's and leaked.\n */\nconst generatedName = () => `motion-view-${nameCount++}`\n\nconst isGeneratedName = (name: string) => name.startsWith(\"motion-view-\")\n\n/**\n * Tag a captured element with a `view-transition-class` so authors can target\n * its generated layer from CSS (e.g. `::view-transition-group(.hero)`) without\n * the opaque generated name. Tracked in `classed` - separate from the generated\n * names in `assigned` - so cleanup removes the class without ever stripping an\n * author's own inline `view-transition-name`.\n */\nfunction tagClass(\n    element: Element,\n    className: string | undefined,\n    classed: Element[]\n) {\n    if (!className) return\n    ;(element as HTMLElement).style?.setProperty(\n        \"view-transition-class\",\n        className\n    )\n    classed.push(element)\n}\n\n/**\n * Set the element's `view-transition-group` so its layer reconstructs the DOM\n * hierarchy in the pseudo-tree (`contain`) - or stays flat (`none`). Tracked in\n * `grouped` for cleanup. When the element clips (any non-`visible` overflow) its\n * name is recorded in `clipChildren` so the caller can clip the nested children\n * (`::view-transition-group-children(name)`), mirroring the live clip through\n * the whole transition rather than only at the live-DOM handoff.\n *\n * Ignored by browsers without nested view-transition groups, where it harmlessly\n * degrades to the flat default.\n */\nfunction applyGroup(\n    element: Element,\n    name: string,\n    group: string | undefined,\n    grouped: Element[],\n    clipChildren?: Set<string>\n) {\n    if (!group) return\n    ;(element as HTMLElement).style?.setProperty(\"view-transition-group\", group)\n    grouped.push(element)\n\n    if (group !== \"none\" && clipChildren) {\n        const style = getComputedStyle(element)\n        if (style.overflowX !== \"visible\" || style.overflowY !== \"visible\") {\n            clipChildren.add(name)\n        }\n    }\n}\n\n/**\n * Resolve a selector/Element to elements and ensure each one carries a\n * `view-transition-name` we can target from script.\n *\n * Author-defined names are reused as-is. Elements that are unnamed (or use\n * the browser's `auto`/`match-element`, whose generated name is not exposed\n * to script) are given a unique generated name, set inline so it's captured,\n * and tracked in `assigned` for later cleanup.\n *\n * `registry` maps each Element to its name so the same element keeps its name\n * across both captures (before and after the update), which is what allows a\n * persistent element to animate as a single `group` layer.\n */\nexport function assignViewTransitionNames(\n    definition: ElementOrSelector,\n    registry: Map<Element, string>,\n    assigned: Element[],\n    forcedNames?: string[],\n    className?: string,\n    classed: Element[] = [],\n    group?: string,\n    grouped: Element[] = [],\n    clipChildren?: Set<string>\n): string[] {\n    const elements = resolveElements(definition)\n\n    /**\n     * The new end of a paired morph: give each element the matching name from\n     * the old end (by index) so the two share one layer and morph. If the new\n     * end resolves to *more* elements than the old end named, the extras have no\n     * counterpart - give them a fresh name so they animate as newcomers rather\n     * than being silently left unnamed. We return the names actually assigned\n     * (sized to the resolved elements), not the raw `forcedNames`, so stagger\n     * totals and the layer set stay in step with what's on the page.\n     */\n    if (forcedNames) {\n        return elements.map((element, i) => {\n            const existing = registry.get(element)\n            if (existing) return existing\n\n            const name = forcedNames[i] ?? generatedName()\n            ;(element as HTMLElement).style?.setProperty(\n                \"view-transition-name\",\n                name\n            )\n            assigned.push(element)\n            registry.set(element, name)\n            tagClass(element, className, classed)\n            applyGroup(element, name, group, grouped, clipChildren)\n\n            return name\n        })\n    }\n\n    /**\n     * Read every current name up front, before assigning any. Interleaving the\n     * reads with the inline `setProperty` writes below would dirty styles\n     * between reads and force a style recalc per element; batching the reads\n     * keeps it to one. Elements already in the registry keep their name and\n     * need no read.\n     */\n    const currentNames = elements.map((element) =>\n        registry.has(element)\n            ? undefined\n            : getComputedStyle(element).getPropertyValue(\"view-transition-name\")\n    )\n\n    return elements.map((element, i) => {\n        const existing = registry.get(element)\n        if (existing) return existing\n\n        const current = currentNames[i]\n\n        let name: string\n        if (\n            current &&\n            current !== \"none\" &&\n            current !== \"auto\" &&\n            current !== \"match-element\" &&\n            !isGeneratedName(current)\n        ) {\n            /**\n             * The author already named this layer - target it as-is and leave\n             * it to them to clean up. `auto`/`match-element` are overridden\n             * because their generated name is not exposed to script, and a\n             * stale `motion-view-*` (e.g. left by an interrupted transition) is\n             * re-owned rather than adopted as an author name and leaked.\n             */\n            name = current\n        } else {\n            name = generatedName()\n            ;(element as HTMLElement).style?.setProperty(\n                \"view-transition-name\",\n                name\n            )\n            assigned.push(element)\n        }\n\n        registry.set(element, name)\n        tagClass(element, className, classed)\n        applyGroup(element, name, group, grouped, clipChildren)\n\n        return name\n    })\n}\n\n/**\n * Remove the `view-transition-name`s we generated and the\n * `view-transition-class`es we applied. Author-defined names are never touched\n * (they're not in `assigned`). Safe to call more than once (e.g. on both a\n * finished and an interrupted transition).\n */\nexport function releaseViewTransitionNames(\n    assigned: Element[],\n    classed: Element[] = [],\n    grouped: Element[] = []\n): void {\n    for (const element of assigned) {\n        ;(element as HTMLElement).style?.removeProperty(\"view-transition-name\")\n    }\n    for (const element of classed) {\n        ;(element as HTMLElement).style?.removeProperty(\"view-transition-class\")\n    }\n    for (const element of grouped) {\n        ;(element as HTMLElement).style?.removeProperty(\"view-transition-group\")\n    }\n}\n","export function chooseLayerType(\n    valueName: \"layout\" | \"enter\" | \"exit\" | \"new\" | \"old\"\n): \"group\" | \"old\" | \"new\" {\n    if (valueName === \"layout\") return \"group\"\n    if (valueName === \"enter\" || valueName === \"new\") return \"new\"\n    return \"old\"\n}\n","let pendingRules: Record<string, Record<string, string>> = {}\n\nlet style: HTMLStyleElement | null = null\n\nexport const css = {\n    set: (selector: string, values: Record<string, string>) => {\n        pendingRules[selector] = values\n    },\n\n    commit: () => {\n        if (!style) {\n            style = document.createElement(\"style\")\n            style.id = \"motion-view\"\n        }\n\n        let cssText = \"\"\n\n        for (const selector in pendingRules) {\n            const rule = pendingRules[selector]\n            cssText += `${selector} {\\n`\n            for (const [property, value] of Object.entries(rule)) {\n                cssText += `  ${property}: ${value};\\n`\n            }\n            cssText += \"}\\n\"\n        }\n\n        style.textContent = cssText\n        document.head.appendChild(style)\n\n        pendingRules = {}\n    },\n\n    remove: () => {\n        if (style && style.parentElement) {\n            style.parentElement.removeChild(style)\n        }\n    },\n}\n","export function getViewAnimationLayerInfo(pseudoElement: string) {\n    const match = pseudoElement.match(\n        // `group-children` (nested transitions) before `group` so it wins.\n        /::view-transition-(old|new|group-children|group|image-pair)\\((.*?)\\)/\n    )\n    if (!match) return null\n\n    return { layer: match[2], type: match[1] }\n}\n","export function getViewAnimations() {\n    return document.getAnimations().filter((animation) => {\n        const { effect } = animation\n        return (\n            !!effect &&\n            effect.target === document.documentElement &&\n            (effect as KeyframeEffect).pseudoElement?.startsWith(\n                \"::view-transition\"\n            )\n        )\n    })\n}\n","import { ViewTransitionTarget, ViewTransitionTargetDefinition } from \"../types\"\n\nexport function hasTarget(\n    target: ViewTransitionTargetDefinition,\n    targets: Map<ViewTransitionTargetDefinition, ViewTransitionTarget>\n) {\n    return targets.has(target) && Object.keys(targets.get(target)!).length > 0\n}\n","import { secondsToMilliseconds, warnOnce } from \"motion-utils\"\nimport { GroupAnimation } from \"../animation/GroupAnimation\"\nimport { NativeAnimation } from \"../animation/NativeAnimation\"\nimport { NativeAnimationWrapper } from \"../animation/NativeAnimationWrapper\"\nimport { AnimationPlaybackControls, DOMKeyframesDefinition } from \"../animation/types\"\nimport { getValueTransition } from \"../animation/utils/get-value-transition\"\nimport { mapEasingToNativeEasing } from \"../animation/waapi/easing/map-easing\"\nimport { applyGeneratorOptions } from \"../animation/waapi/utils/apply-generator\"\nimport { cornerRadiusProps } from \"../utils/border-radius\"\nimport { ElementOrSelector, resolveElements } from \"../utils/resolve-elements\"\nimport type { ViewTransitionBuilder } from \"./index\"\nimport { ViewTransitionTarget, ViewTransitionTargetDefinition } from \"./types\"\nimport {\n    assignViewTransitionNames,\n    releaseViewTransitionNames,\n} from \"./utils/assign-names\"\nimport { chooseLayerType } from \"./utils/choose-layer-type\"\nimport { css } from \"./utils/css\"\nimport { getViewAnimationLayerInfo } from \"./utils/get-layer-info\"\nimport { getViewAnimations } from \"./utils/get-view-animations\"\nimport { hasTarget } from \"./utils/has-target\"\n\nconst definitionNames = [\"layout\", \"enter\", \"exit\", \"new\", \"old\"] as const\n\ntype CornerRadii = Record<(typeof cornerRadiusProps)[number], string>\n\n/**\n * Whether a computed border-radius is square (every component zero). Splitting\n * on whitespace handles two-value/elliptical radii like \"0px 20px\" - a leading\n * `parseFloat` alone would misread the non-zero vertical radius as square.\n */\nconst isSquareRadius = (radius: string) =>\n    radius.split(\" \").every((value) => parseFloat(value) === 0)\n\n/**\n * The `ViewTransitionTarget` buckets driving each generated layer type, in\n * priority order - the inverse of `chooseLayerType`. The new view is driven by\n * `new`/`enter`, the old by `old`/`exit`. `group-children`/`image-pair` have no\n * bucket; they follow the default layout timing.\n */\nconst typeBuckets: Record<string, (keyof ViewTransitionTarget)[]> = {\n    group: [\"layout\"],\n    new: [\"new\", \"enter\"],\n    old: [\"old\", \"exit\"],\n}\n\n/**\n * Default \"absent\" origin for a single-value keyframe, by pseudo type, so e.g.\n * `enter({ scale: 1 })` grows in from 0.85 and `exit({ opacity: 0 })` fades\n * from 1. `enter` prefers the matching `exit` value over these (see below).\n */\nconst ORIGIN_DEFAULTS: Record<string, Record<string, number>> = {\n    new: { opacity: 0, scale: 0.85 },\n    old: { opacity: 1, scale: 1 },\n}\n\n/**\n * How much two box aspect ratios must differ before a morph is treated as\n * aspect-changing (and so worth cropping). Matches the projection engine's\n * `preserve-aspect` threshold, so small layout jitter doesn't trigger a crop.\n */\nconst ASPECT_TOLERANCE = 0.2\n\nexport function startViewAnimation(\n    builder: ViewTransitionBuilder\n): Promise<GroupAnimation> {\n    const {\n        update,\n        targets,\n        resolveDefs,\n        cropOverride,\n        pairs,\n        classNames,\n        flatGroups,\n        options: defaultOptions,\n    } = builder\n\n    if (!document.startViewTransition) {\n        // An async IIFE (not `new Promise(async …)`) so a throwing/rejecting\n        // update rejects this promise rather than leaving it unsettled.\n        return (async () => {\n            await update()\n            return new GroupAnimation([])\n        })()\n    }\n\n    /**\n     * Resolve any selector/Element targets to layer names, assigning a\n     * `view-transition-name` to each element as we go. We run this before the\n     * update (so the elements are captured in the old snapshot) and again\n     * after it (for the new snapshot). An element present in both keeps the\n     * same name and animates as a single `group` layer.\n     */\n    const nameRegistry = new Map<Element, string>()\n    const assigned: Element[] = []\n    /**\n     * Elements we tagged with a `view-transition-class` (via `.class()`),\n     * tracked separately from `assigned` so cleanup removes the class without\n     * ever stripping an author's own inline `view-transition-name`.\n     */\n    const classed: Element[] = []\n    /**\n     * Elements we set a `view-transition-group` on (for nesting), tracked for\n     * cleanup. `clipChildren` collects the names of nested parents that clip in\n     * the live layout, so their `::view-transition-group-children` is clipped\n     * through the transition - not just once the live DOM takes back over.\n     */\n    const grouped: Element[] = []\n    const clipChildren = new Set<string>()\n    const layerTargets = new Map<string, ViewTransitionTarget>()\n    const croppedNames = new Set<string>()\n    /**\n     * Each layer's explicit `.crop(true | false)` override (by resolved name),\n     * so `finalizeCrop` can let an author's choice win over the morph default.\n     */\n    const cropForName = new Map<string, boolean>()\n    /**\n     * Each layer's stagger position (index + total) within its subject, per\n     * snapshot. Resolving against the snapshot the layer belongs to keeps\n     * stagger correct when `update()` replaces the matched elements, and lets\n     * us skip a layer that's absent from a snapshot (e.g. an exited element\n     * has no `new` pseudo-element).\n     */\n    const layerStagger = new Map<\n        string,\n        { old?: [number, number]; new?: [number, number] }\n    >()\n    /**\n     * Names allocated for a paired subject in the old snapshot, replayed onto\n     * its new-snapshot target so both ends share a layer and morph.\n     */\n    const pairNames = new Map<ViewTransitionTargetDefinition, string[]>()\n    /**\n     * The old (`from`) elements of each paired subject, so their names can be\n     * transferred off before the new (`to`) elements inherit them.\n     */\n    const pairFrom = new Map<ViewTransitionTargetDefinition, Element[]>()\n\n    const resolveLayers = (phase: \"old\" | \"new\") => {\n        targets.forEach((target, definition) => {\n            const className = classNames.get(definition)\n            /**\n             * Nest each resolved layer under its DOM-ancestor layer by default\n             * (`contain`), so an ancestor's clip/transform/opacity reach it\n             * through the transition; `.group(false)` opts a subject out (`none`)\n             * to stay flat and escape. Skipped for root / pre-named layers, which\n             * aren't elements we resolve and style.\n             */\n            const group =\n                definition === \"root\" || !resolveDefs.has(definition)\n                    ? undefined\n                    : flatGroups.has(definition)\n                      ? \"none\"\n                      : \"contain\"\n            let names: string[]\n            if (definition === \"root\" || !resolveDefs.has(definition)) {\n                names = [definition as string]\n            } else if (pairs.has(definition)) {\n                /**\n                 * Paired morph: name the old target in the old snapshot, then\n                 * force the same name(s) onto the new target in the new one, so\n                 * two different elements morph as a single layer.\n                 */\n                if (phase === \"old\") {\n                    pairFrom.set(\n                        definition,\n                        resolveElements(definition as ElementOrSelector)\n                    )\n                    names = assignViewTransitionNames(\n                        definition as ElementOrSelector,\n                        nameRegistry,\n                        assigned,\n                        undefined,\n                        className,\n                        classed,\n                        group,\n                        grouped,\n                        clipChildren\n                    )\n                    pairNames.set(definition, names)\n                } else {\n                    /**\n                     * Transfer the name(s) off the `from` elements before the\n                     * `to` elements inherit them. A `from` that survives into\n                     * the new snapshot (e.g. hidden with `visibility: hidden`\n                     * rather than removed) would otherwise keep the name and\n                     * collide - \"duplicate view-transition-name\".\n                     */\n                    for (const el of pairFrom.get(definition) ?? []) {\n                        ;(el as HTMLElement).style?.removeProperty(\n                            \"view-transition-name\"\n                        )\n                        /**\n                         * Drop the old end from the registry too, so the new\n                         * end alone supplies this name's `new` crop radii - we\n                         * neither re-measure nor get ordered by a stale element.\n                         */\n                        nameRegistry.delete(el)\n                    }\n                    names = assignViewTransitionNames(\n                        pairs.get(definition) as ElementOrSelector,\n                        nameRegistry,\n                        assigned,\n                        pairNames.get(definition),\n                        className,\n                        classed,\n                        group,\n                        grouped,\n                        clipChildren\n                    )\n                }\n            } else {\n                names = assignViewTransitionNames(\n                    definition as ElementOrSelector,\n                    nameRegistry,\n                    assigned,\n                    undefined,\n                    className,\n                    classed,\n                    group,\n                    grouped,\n                    clipChildren\n                )\n            }\n\n            // Record any explicit `.crop(true | false)` per resolved name; the\n            // crop set itself is computed later by `finalizeCrop` (it needs both\n            // snapshots to know which morphs change aspect ratio).\n            const override = cropOverride.get(definition)\n\n            names.forEach((name, index) => {\n                /**\n                 * If two subjects resolve to the same element, merge their\n                 * definitions so neither subject's animations are dropped.\n                 */\n                const existing = layerTargets.get(name)\n                layerTargets.set(\n                    name,\n                    existing && existing !== target\n                        ? { ...existing, ...target }\n                        : target\n                )\n\n                if (override !== undefined) cropForName.set(name, override)\n\n                const stagger = layerStagger.get(name) ?? {}\n                stagger[phase] = [index, names.length]\n                layerStagger.set(name, stagger)\n            })\n        })\n    }\n\n    /**\n     * The stagger index/total for a layer, resolved against the snapshot it\n     * belongs to. Returns index -1 when the layer is absent from that snapshot\n     * so the caller can skip a pseudo-element that doesn't exist.\n     */\n    const staggerPosition = (name: string, type: string) => {\n        const stagger = layerStagger.get(name)\n        const position =\n            type === \"old\"\n                ? stagger?.old\n                : type === \"new\"\n                  ? stagger?.new\n                  : // group / group-children / image-pair persist across both.\n                    stagger?.new ?? stagger?.old\n        return position ?? ([-1, 1] as const)\n    }\n\n    /**\n     * Merge default + per-layer transition options for a generated layer and\n     * resolve any stagger/delay function against this element's position. Used\n     * by both the morph-retiming and crop corner-radius passes.\n     */\n    const resolveLayerTransition = (\n        target: ViewTransitionTarget | undefined,\n        type: string,\n        transitionName: string,\n        index: number,\n        total: number\n    ) => {\n        const transition = mergeTransition(\n            getValueTransition(defaultOptions, transitionName),\n            getValueTransition(\n                (layerOptions(target, type) ?? {}) as any,\n                transitionName\n            )\n        )\n\n        if (typeof transition.delay === \"function\") {\n            transition.delay = transition.delay(index, total)\n        }\n\n        return transition\n    }\n\n    /**\n     * Resolve a layer's group (`layout`) timing to plain WAAPI values: native\n     * ms `delay`/`duration` and a baked `ease`. The single source of group\n     * timing, shared by the generated-group retiming and the crop corner-radius\n     * pass so the rounded clip animates on exactly the box's timing. It returns\n     * no generator `type` (the WAAPI-only `NativeAnimation` rejects a string\n     * type) nor `repeat`/`times` (which the group's `updateTiming` ignores), so\n     * none of them can leak into the radius animation and desync it.\n     */\n    const resolveGroupTiming = (name: string) => {\n        const [index, total] = staggerPosition(name, \"group\")\n        const transition = resolveLayerTransition(\n            layerTargets.get(name),\n            \"group\",\n            \"layout\",\n            index === -1 ? 0 : index,\n            total\n        )\n        transition.duration &&= secondsToMilliseconds(transition.duration)\n        const { delay = 0, duration, ease } = applyGeneratorOptions(transition)\n        return { delay: secondsToMilliseconds(delay), duration, ease }\n    }\n\n    /**\n     * Each layer's measured box + corner radii per snapshot. The box lets\n     * `finalizeCrop` tell whether a morph's aspect ratio changed (the only case\n     * worth cropping); the radii let a cropped morph's group clip animate each\n     * corner from the old element's radius to the new element's, keeping it\n     * rounded where `overflow: clip` would otherwise square the corners.\n     *\n     * We never flatten the source for capture (a snapshot is a paint of the live\n     * DOM, so squaring an element just for its capture would flash one real\n     * square frame). For an aspect-changing morph `object-fit: cover` crops each\n     * snapshot's own baked corners off-screen mid-morph, so the animated clip is\n     * the only visible corner; a near-same-aspect forced crop (`.crop(true)`)\n     * can't hide the outgoing snapshot's silhouette, but the endpoints coincide.\n     */\n    const cropMeasurements = new Map<\n        string,\n        {\n            old?: { width: number; height: number; radii: CornerRadii }\n            new?: { width: number; height: number; radii: CornerRadii }\n        }\n    >()\n\n    const measureLayers = (phase: \"old\" | \"new\") =>\n        nameRegistry.forEach((name, element) => {\n            const el = element as HTMLElement\n            const rect = el.getBoundingClientRect?.()\n            if (rect && rect.height) {\n                const style = getComputedStyle(el)\n                const radii = {} as CornerRadii\n                for (const corner of cornerRadiusProps) {\n                    radii[corner] = style[corner]\n                }\n                const entry = cropMeasurements.get(name) ?? {}\n                entry[phase] = { width: rect.width, height: rect.height, radii }\n                cropMeasurements.set(name, entry)\n            }\n        })\n\n    /**\n     * With both snapshots measured, settle which layers crop. The default crops\n     * only a morph whose aspect ratio *changes* between snapshots - the one case\n     * where `object-fit: cover` does real work. A same-aspect morph or a\n     * fade-only layer is left uncropped: its corners scale naturally (no flash\n     * from squaring, no `overflow: clip` eating its shadow) and a backdrop can't\n     * be clipped to nothing. An explicit `.crop(true | false)` overrides either\n     * way. Runs after both snapshots are measured, since aspect needs both.\n     */\n    const finalizeCrop = () => {\n        croppedNames.clear()\n        for (const name of layerStagger.keys()) {\n            if (name === \"root\") continue\n            // An explicit `.crop(true | false)` wins; otherwise crop a morph\n            // whose aspect ratio changed.\n            if (cropForName.get(name) ?? aspectChanged(name)) {\n                croppedNames.add(name)\n            }\n        }\n    }\n\n    /**\n     * Whether a layer is a morph whose box aspect ratio changed between\n     * snapshots (beyond a small tolerance). Fade-only layers (one snapshot) are\n     * never \"changed\".\n     */\n    const aspectChanged = (name: string) => {\n        const box = cropMeasurements.get(name)\n        if (!box?.old || !box?.new || !box.old.height || !box.new.height) {\n            return false\n        }\n        return (\n            Math.abs(\n                box.old.width / box.old.height -\n                    box.new.width / box.new.height\n            ) > ASPECT_TOLERANCE\n        )\n    }\n\n    /**\n     * Write the persistent view-transition CSS: suppress root capture when the\n     * root has no animations of its own; force linear timing (baked into the\n     * keyframes, so we can retime later via updateTiming); and clip +\n     * object-fit: cover every cropped morph (the UA default overflows on\n     * aspect-ratio change).\n     *\n     * `css.commit` replaces rather than appends, so we re-set the full rule set\n     * each call - the crop rules are only known after `finalizeCrop` runs in the\n     * update callback, so the second call writes them.\n     */\n    const commitViewCSS = () => {\n        if (!hasTarget(\"root\", targets)) {\n            css.set(\":root\", { \"view-transition-name\": \"none\" })\n        }\n\n        css.set(\n            \"::view-transition-group(*), ::view-transition-old(*), ::view-transition-new(*)\",\n            { \"animation-timing-function\": \"linear !important\" }\n        )\n\n        croppedNames.forEach((name) => {\n            css.set(`::view-transition-group(${name})`, { overflow: \"clip\" })\n            css.set(\n                `::view-transition-old(${name}), ::view-transition-new(${name})`,\n                { width: \"100%\", height: \"100%\", \"object-fit\": \"cover\" }\n            )\n        })\n\n        /**\n         * Clip the nested children of any layer that clips in the live layout,\n         * so a wrapper crops its child for the whole morph (mirroring the DOM)\n         * rather than only at the live-DOM handoff. No-op on browsers without\n         * nested view-transition groups.\n         */\n        clipChildren.forEach((name) => {\n            css.set(`::view-transition-group-children(${name})`, {\n                overflow: \"clip\",\n            })\n        })\n\n        css.commit() // Write\n    }\n\n    const cleanup = () => {\n        releaseViewTransitionNames(assigned, classed, grouped)\n        css.remove() // Write\n    }\n\n    const callback = async () => {\n        await update()\n\n        /**\n         * Re-resolve so elements created by the update are named for the new\n         * snapshot, then measure them. With both snapshots measured we can\n         * settle the crop set (aspect-changing morphs + forced).\n         */\n        resolveLayers(\"new\")\n        measureLayers(\"new\")\n        finalizeCrop()\n\n        /**\n         * Re-commit the crop CSS unconditionally: `finalizeCrop` is computed\n         * here (after both snapshots are measured), so the clip rules must be\n         * (re)written to match the settled set.\n         */\n        commitViewCSS()\n    }\n\n    let transition: ViewTransition\n    try {\n        resolveLayers(\"old\")\n        /**\n         * Measure the old snapshot against the optimistic crop set (the new\n         * snapshot doesn't exist yet, so aspect change can't be known here;\n         * `finalizeCrop` settles it post-update).\n         */\n        measureLayers(\"old\")\n        commitViewCSS()\n        transition = document.startViewTransition(callback)\n    } catch (error) {\n        /**\n         * The prelude writes inline names before the transition exists. If it\n         * throws (e.g. startViewTransition rejects in a bad UA state), release\n         * them so we neither leak DOM state nor stall the queue on a promise\n         * that never settles - hand back a rejection it can advance past.\n         */\n        cleanup()\n        return Promise.reject(error)\n    }\n\n    transition.finished.finally(cleanup)\n\n    return new Promise<GroupAnimation>((resolve, reject) => {\n        transition.ready\n            .then(() => {\n                const generatedViewAnimations = getViewAnimations()\n\n                const animations: AnimationPlaybackControls[] = []\n\n                /**\n                 * Create animations for each of our explicitly-defined subjects.\n                 * `opacityAnimated` additionally tracks which `${name}:${type}`\n                 * we faded, so we can keep the UA `plus-lighter` blend only for a\n                 * genuine opacity crossfade (both sides fading) and drop it for a\n                 * slide/transform, where additive compositing would flash bright.\n                 */\n                const explicitlyAnimated = new Set<string>()\n                const opacityAnimated = new Set<string>()\n                layerTargets.forEach((target, name) => {\n                    const stagger = layerStagger.get(name)\n                    /**\n                     * Presence: `enter` only fires for a pure newcomer (a new\n                     * view with no old), `exit` only for a pure leaver. A\n                     * survivor (both) gets neither - it just morphs.\n                     */\n                    const enterApplies = !!stagger?.new && !stagger?.old\n                    const exitApplies = !!stagger?.old && !stagger?.new\n\n                    for (const key of definitionNames) {\n                        if (!target[key]) continue\n                        if (key === \"enter\" && !enterApplies) continue\n                        if (key === \"exit\" && !exitApplies) continue\n\n                        const type = chooseLayerType(\n                            key as keyof ViewTransitionTarget\n                        )\n                        const [index, total] = staggerPosition(name, type)\n                        // Skip a layer absent from its snapshot.\n                        if (index === -1) continue\n\n                        const { keyframes, options } =\n                            target[key as keyof ViewTransitionTarget]!\n\n                        for (let [valueName, valueKeyframes] of Object.entries(\n                            keyframes\n                        )) {\n                            // Skip only missing values - `0` (e.g. opacity: 0)\n                            // is valid and must reach the from-value inference.\n                            if (valueKeyframes == null) continue\n\n                            /**\n                             * The view path hands keyframes straight to WAAPI,\n                             * so Motion's `x`/`y` shorthands (compiled to\n                             * `transform` only via the value pipeline) have no\n                             * effect. Warn and skip - use `transform`/`translate`.\n                             */\n                            if (valueName === \"x\" || valueName === \"y\") {\n                                warnOnce(\n                                    false,\n                                    `animateView() animates view-transition layers with CSS properties; the \"${valueName}\" shorthand has no effect - use transform, e.g. { transform: \"translateX(40px)\" }.`\n                                )\n                                continue\n                            }\n\n                            /**\n                             * enter/exit win over new/old on a shared property -\n                             * skip it here when the gated bucket also defines it.\n                             */\n                            if (\n                                key === \"new\" &&\n                                enterApplies &&\n                                target.enter?.keyframes[\n                                    valueName as keyof DOMKeyframesDefinition\n                                ] != null\n                            ) {\n                                continue\n                            }\n                            if (\n                                key === \"old\" &&\n                                exitApplies &&\n                                target.exit?.keyframes[\n                                    valueName as keyof DOMKeyframesDefinition\n                                ] != null\n                            ) {\n                                continue\n                            }\n\n                            const valueOptions = mergeTransition(\n                                getValueTransition(\n                                    defaultOptions as any,\n                                    valueName\n                                ),\n                                getValueTransition(options as any, valueName)\n                            )\n\n                            /**\n                             * Infer an origin for a single-value keyframe. An\n                             * `enter` mirrors the matching `exit` value (a\n                             * defined exit reverses into the enter for free);\n                             * otherwise the per-type default (opacity 0/1, scale\n                             * 0.85). No default -> left as-is (animates from the\n                             * live value).\n                             *\n                             * `new`/`old` fire for survivors too, where only the\n                             * opacity crossfade default applies - a transform\n                             * default like scale 0.85 would pop a persisting\n                             * element, so gate it on the layer actually\n                             * entering/leaving.\n                             */\n                            if (!Array.isArray(valueKeyframes)) {\n                                const exitValue =\n                                    key === \"enter\"\n                                        ? target.exit?.keyframes[\n                                              valueName as keyof DOMKeyframesDefinition\n                                          ]\n                                        : undefined\n                                const allowDefault =\n                                    valueName === \"opacity\" ||\n                                    (type === \"new\" ? enterApplies : exitApplies)\n                                const from =\n                                    exitValue != null\n                                        ? Array.isArray(exitValue)\n                                            ? exitValue[exitValue.length - 1]\n                                            : exitValue\n                                        : allowDefault\n                                          ? ORIGIN_DEFAULTS[type]?.[valueName]\n                                          : undefined\n                                if (from !== undefined) {\n                                    valueKeyframes = [from, valueKeyframes]\n                                }\n                            }\n\n                            /**\n                             * Resolve stagger function if provided, per element\n                             * across this subject's resolved layers.\n                             */\n                            if (typeof valueOptions.delay === \"function\") {\n                                valueOptions.delay = valueOptions.delay(\n                                    index,\n                                    total\n                                )\n                            }\n\n                            valueOptions.duration &&= secondsToMilliseconds(\n                                valueOptions.duration\n                            )\n\n                            valueOptions.delay &&= secondsToMilliseconds(\n                                valueOptions.delay\n                            )\n\n                            animations.push(\n                                new NativeAnimation({\n                                    ...valueOptions,\n                                    element: document.documentElement,\n                                    name: valueName,\n                                    pseudoElement: `::view-transition-${type}(${name})`,\n                                    keyframes: valueKeyframes,\n                                })\n                            )\n                            explicitlyAnimated.add(`${name}:${type}`)\n                            if (valueName === \"opacity\") {\n                                opacityAnimated.add(`${name}:${type}`)\n                            }\n                        }\n                    }\n                })\n\n                /**\n                 * Handle browser generated animations\n                 */\n                for (const animation of generatedViewAnimations) {\n                    if (animation.playState === \"finished\") continue\n\n                    const { effect } = animation\n                    if (!effect || !(effect instanceof KeyframeEffect)) continue\n\n                    const { pseudoElement } = effect\n                    if (!pseudoElement) continue\n\n                    const name = getViewAnimationLayerInfo(pseudoElement)\n                    if (!name) continue\n\n                    const targetDefinition = layerTargets.get(name.layer)\n\n                    /**\n                     * We built our own animation for this layer, so drop the\n                     * browser-generated fade we're replacing. The UA\n                     * `plus-lighter` blend is a *separate* generated animation on\n                     * the same pseudo (it sets `mix-blend-mode` in its keyframes):\n                     * keep it *only* for a true opacity crossfade - both sides\n                     * fading - so a symmetric crossfade composites without\n                     * darkening, but a slide/transform (where both layers stay\n                     * opaque and overlap) doesn't flash bright from the addition.\n                     */\n                    if (explicitlyAnimated.has(`${name.layer}:${name.type}`)) {\n                        const isCrossfade =\n                            opacityAnimated.has(`${name.layer}:new`) &&\n                            opacityAnimated.has(`${name.layer}:old`)\n                        if (\n                            isCrossfade &&\n                            effect\n                                .getKeyframes()\n                                .some((keyframe) => keyframe.mixBlendMode)\n                        ) {\n                            animations.push(new NativeAnimationWrapper(animation))\n                        } else {\n                            animation.cancel()\n                        }\n                        continue\n                    }\n\n                    /**\n                     * Drop the orphaned half of the default crossfade. The UA\n                     * fades old out and new in as a *pair*; if the opposing half\n                     * was explicitly overridden with something other than an\n                     * opacity fade (a clip or transform reveal), this side's\n                     * default opacity fade has no partner - left to run it would\n                     * dissolve what should be a static backdrop (e.g.\n                     * `.new({ clipPath })` should reveal over a still old view,\n                     * not fade the old out around the growing clip). Cancel it -\n                     * and its `plus-lighter` sibling on the same pseudo, which\n                     * would otherwise flash bright where the two opaque layers\n                     * overlap. A genuine crossfade (the opposing side also fading\n                     * opacity) keeps both halves and is handled above.\n                     */\n                    const opposite =\n                        name.type === \"old\"\n                            ? \"new\"\n                            : name.type === \"new\"\n                              ? \"old\"\n                              : undefined\n                    if (\n                        opposite &&\n                        explicitlyAnimated.has(\n                            `${name.layer}:${opposite}`\n                        ) &&\n                        !opacityAnimated.has(`${name.layer}:${opposite}`)\n                    ) {\n                        animation.cancel()\n                        continue\n                    }\n\n                    /**\n                     * Otherwise retime the browser-generated animation to\n                     * Motion's timing. This auto-enables the layout (group)\n                     * morph for any resolved/named target, and applies the\n                     * default timing to old/new layers we haven't explicitly\n                     * overridden.\n                     *\n                     * group + group-children both follow the layout timing so\n                     * the nesting container stays in sync with the morph.\n                     */\n                    /**\n                     * A survivor's old + new are the two halves of one\n                     * `plus-lighter` crossfade. They must share identical timing\n                     * (so their opacities stay mirrored and sum to 1 - else the\n                     * additive blend flashes bright wherever both are partly\n                     * visible) and fade linearly (the bounce belongs on the\n                     * group's geometry, not the opacity). So time them as the\n                     * group, rather than via their own - potentially staggered,\n                     * or enter/exit-derived - old/new options.\n                     */\n                    const stagger = layerStagger.get(name.layer)\n                    const isMorphCrossfade =\n                        (name.type === \"old\" || name.type === \"new\") &&\n                        !!stagger?.old &&\n                        !!stagger?.new\n\n                    let timing: {\n                        delay: number\n                        duration?: number\n                        easing: string\n                    }\n                    if (name.type.startsWith(\"group\")) {\n                        // group + group-children follow the resolved group\n                        // timing - the single source shared with the crop\n                        // corner-radius pass below.\n                        const { delay, duration, ease } = resolveGroupTiming(\n                            name.layer\n                        )\n                        timing = {\n                            delay,\n                            duration,\n                            easing: mapEasingToNativeEasing(\n                                ease,\n                                duration!\n                            ) as string,\n                        }\n                    } else {\n                        const timingType = isMorphCrossfade ? \"group\" : name.type\n                        const [index, total] = staggerPosition(\n                            name.layer,\n                            timingType\n                        )\n                        const transitionName =\n                            timingType === \"group\" ? \"layout\" : \"\"\n                        let animationTransition = resolveLayerTransition(\n                            targetDefinition,\n                            timingType,\n                            transitionName,\n                            index === -1 ? 0 : index,\n                            total\n                        )\n\n                        /**\n                         * The crossfade should resolve at the spring's\n                         * *perceptual* (visual) duration - the geometry can keep\n                         * bouncing, but the opacity shouldn't drag through the\n                         * settle. So capture `visualDuration` before\n                         * `applyGeneratorOptions` replaces it with the full\n                         * overshoot duration, and use it for the fade.\n                         */\n                        const visualDuration = animationTransition.visualDuration\n\n                        animationTransition.duration &&= secondsToMilliseconds(\n                            animationTransition.duration\n                        )\n\n                        animationTransition =\n                            applyGeneratorOptions(animationTransition)\n\n                        timing = {\n                            delay: secondsToMilliseconds(\n                                animationTransition.delay ?? 0\n                            ),\n                            duration:\n                                isMorphCrossfade && visualDuration !== undefined\n                                    ? secondsToMilliseconds(visualDuration)\n                                    : animationTransition.duration,\n                            easing: isMorphCrossfade\n                                ? \"linear\"\n                                : (mapEasingToNativeEasing(\n                                      animationTransition.ease,\n                                      animationTransition.duration!\n                                  ) as string),\n                        }\n                    }\n\n                    effect.updateTiming(timing)\n\n                    animations.push(new NativeAnimationWrapper(animation))\n                }\n\n                /**\n                 * Round each cropped layer's clip. Its `::view-transition-group`\n                 * has `overflow: clip`, which would otherwise square the corners\n                 * mid-morph; animate each corner from the old element's radius to\n                 * the new element's so the crop stays rounded. Timed as the group\n                 * (`layout`) so the radius tracks the morphing box.\n                 */\n                cropMeasurements.forEach((entry, name) => {\n                    if (!croppedNames.has(name)) return\n\n                    // Reuse the group's resolved timing - native ms delay/\n                    // duration + a baked ease, with no generator `type` or\n                    // repeat/times to leak into (or throw inside) NativeAnimation.\n                    const { delay, duration, ease } = resolveGroupTiming(name)\n\n                    for (const corner of cornerRadiusProps) {\n                        // `||` (not `??`) so an empty measurement falls back to\n                        // the other snapshot rather than an invalid keyframe.\n                        const from =\n                            entry.old?.radii[corner] ||\n                            entry.new?.radii[corner] ||\n                            \"0px\"\n                        const to =\n                            entry.new?.radii[corner] ||\n                            entry.old?.radii[corner] ||\n                            \"0px\"\n                        // Nothing to round if the corner is square at both ends.\n                        if (isSquareRadius(from) && isSquareRadius(to)) continue\n\n                        animations.push(\n                            new NativeAnimation({\n                                element: document.documentElement,\n                                name: corner,\n                                pseudoElement: `::view-transition-group(${name})`,\n                                keyframes: [from, to],\n                                delay,\n                                duration,\n                                ease,\n                            })\n                        )\n                    }\n                })\n\n                resolve(new GroupAnimation(animations))\n            })\n            .catch(() =>\n                /**\n                 * `ready` rejects when the transition is skipped - no visual\n                 * change, or superseded by an interrupting transition. The DOM\n                 * update still applied, so settle with no animations rather than\n                 * surfacing it as an error to an awaiting caller. A genuine\n                 * failure in `update()` rejects `updateCallbackDone` (already\n                 * settled by now), so propagate that instead.\n                 */\n                transition.updateCallbackDone.then(\n                    () => resolve(new GroupAnimation([])),\n                    reject\n                )\n            )\n    })\n}\n\n/**\n * The options that should time a given generated layer type, so a retimed\n * group/old/new picks up any per-target transition the user provided. Checks\n * the type's buckets in priority order (e.g. `new` before `enter`).\n */\nfunction layerOptions(target: ViewTransitionTarget | undefined, type: string) {\n    for (const bucket of typeBuckets[type] ?? []) {\n        const options = target?.[bucket]?.options\n        if (options) return options\n    }\n}\n\n/**\n * Merge a base transition (e.g. the default `options`) with a per-layer/value\n * override. An explicit `duration` on the override must win over an inherited\n * generator's own timing: a spring prefers `visualDuration`, and\n * `spring.applyToOptions` overwrites `duration` with the computed settle time -\n * so without this the override is silently discarded. Dropping the inherited\n * `type`/`visualDuration` makes the layer a plain tween of that duration, unless\n * it asked for its own generator `type`/`visualDuration`.\n */\nfunction mergeTransition(base: any, override: any) {\n    const merged = { ...base, ...override }\n\n    if (override.duration !== undefined) {\n        if (override.visualDuration === undefined) delete merged.visualDuration\n        if (override.type === undefined) delete merged.type\n    }\n\n    return merged\n}\n","import { removeItem } from \"motion-utils\"\nimport type { ViewTransitionBuilder } from \".\"\nimport { microtask } from \"../frameloop/microtask\"\nimport { startViewAnimation } from \"./start\"\n\nlet builders: ViewTransitionBuilder[] = []\n\nlet current: ViewTransitionBuilder | null = null\n\nfunction next() {\n    current = null\n    const [nextBuilder] = builders\n    if (nextBuilder) start(nextBuilder)\n}\n\nfunction start(builder: ViewTransitionBuilder) {\n    removeItem(builders, builder)\n    current = builder\n    startViewAnimation(builder)\n        .then((animation) => {\n            builder.notifyReady(animation)\n            return animation.finished\n        })\n        // A genuinely failed transition (a throwing update) rejects the\n        // builder; a skipped/interrupted one resolves with no animations (see\n        // start.ts). Either way, advance the queue - else later transitions hang.\n        .catch((error) => builder.notifyReject(error))\n        .finally(next)\n}\n\nfunction processQueue() {\n    /**\n     * Iterate backwards over the builders array. We can ignore the\n     * \"wait\" animations. If we have an interrupting animation in the\n     * queue then we need to batch all preceeding animations into it.\n     * Currently this only batches the update functions but will also\n     * need to batch the targets.\n     */\n    for (let i = builders.length - 1; i >= 0; i--) {\n        const builder = builders[i]\n        const { interrupt } = builder.options\n\n        if (interrupt === \"immediate\") {\n            const batchedUpdates = builders.slice(0, i + 1).map((b) => b.update)\n            const remaining = builders.slice(i + 1)\n\n            builder.update = () => {\n                batchedUpdates.forEach((update) => update())\n            }\n\n            // Put the current builder at the front, followed by any \"wait\" builders\n            builders = [builder, ...remaining]\n\n            break\n        }\n    }\n\n    if (!current || builders[0]?.options.interrupt === \"immediate\") {\n        next()\n    }\n}\n\nexport function addToQueue(builder: ViewTransitionBuilder) {\n    builders.push(builder)\n    microtask.render(processQueue)\n}\n","import { noop } from \"motion-utils\"\nimport type { GroupAnimation } from \"../animation/GroupAnimation\"\nimport { AnimationOptions, DOMKeyframesDefinition } from \"../animation/types\"\nimport { addToQueue } from \"./queue\"\nimport {\n    ViewTransitionOptions,\n    ViewTransitionTarget,\n    ViewTransitionTargetDefinition,\n} from \"./types\"\nimport \"./types.global\"\n\n// Re-export the public view-transition types so they flow out through\n// motion-dom -> framer-motion -> motion alongside `animateView`.\nexport type * from \"./types\"\n\nexport class ViewTransitionBuilder {\n    private currentSubject: ViewTransitionTargetDefinition = \"root\"\n\n    targets = new Map<ViewTransitionTargetDefinition, ViewTransitionTarget>()\n\n    /**\n     * Definitions that must be resolved to elements (and assigned a\n     * `view-transition-name`) rather than treated as pre-named layers.\n     */\n    resolveDefs = new Set<ViewTransitionTargetDefinition>()\n\n    /**\n     * Per-subject crop override: `true` forces the crop (clip + object-fit:\n     * cover + animated corner radii) on, `false` forces it off. A subject with\n     * no entry uses the default - crop only a genuine morph (a layer present in\n     * both snapshots), so a fade-only enter/exit isn't clipped to nothing.\n     */\n    cropOverride = new Map<ViewTransitionTargetDefinition, boolean>()\n\n    /**\n     * Subjects paired with a different new-snapshot target (the second `.add()`\n     * argument), so two distinct elements share one name and morph into each\n     * other - a shared-element transition.\n     */\n    pairs = new Map<\n        ViewTransitionTargetDefinition,\n        ViewTransitionTargetDefinition\n    >()\n\n    /**\n     * A `view-transition-class` to apply to each subject's resolved elements,\n     * so authors can target the generated layers from CSS by class rather than\n     * the opaque generated name.\n     */\n    classNames = new Map<ViewTransitionTargetDefinition, string>()\n\n    /**\n     * Subjects opted out of automatic group nesting via `.group(false)`. Their\n     * layer stays a flat top-level group (`view-transition-group: none`) instead\n     * of nesting under its DOM-ancestor layer - so it animates independently and\n     * escapes an ancestor's clip/transform (e.g. an element that lifts out of a\n     * card and flies across, which nesting would clip to the card).\n     */\n    flatGroups = new Set<ViewTransitionTargetDefinition>()\n\n    update: () => void | Promise<void>\n\n    options: ViewTransitionOptions\n\n    notifyReady: (value: GroupAnimation) => void = noop\n\n    notifyReject: (error: unknown) => void = noop\n\n    private readyPromise = new Promise<GroupAnimation>((resolve, reject) => {\n        this.notifyReady = resolve\n        this.notifyReject = reject\n    })\n\n    constructor(\n        update: () => void | Promise<void>,\n        options: ViewTransitionOptions = {}\n    ) {\n        this.update = update\n        this.options = {\n            interrupt: \"wait\",\n            ...options,\n        }\n        // Avoid an unhandled rejection when a failed transition has no\n        // `.then(_, reject)` handler attached (e.g. fire-and-forget).\n        this.readyPromise.catch(noop)\n        addToQueue(this)\n    }\n\n    /**\n     * Target elements resolved from a selector or Element, each assigned a\n     * `view-transition-name` automatically.\n     *\n     * Passing a second target pairs them: the first is resolved in the old\n     * snapshot and the second in the new, sharing one name so two *different*\n     * elements morph into each other (e.g. `.add(card, \".modal\")`). Symmetric -\n     * pass them the other way round to morph back.\n     */\n    add(\n        subject: ViewTransitionTargetDefinition,\n        newSubject?: ViewTransitionTargetDefinition\n    ) {\n        this.currentSubject = subject\n        this.resolveDefs.add(subject)\n        if (newSubject !== undefined) this.pairs.set(subject, newSubject)\n        // Register the subject so it participates (and gets an automatic\n        // layout/morph animation) even without an explicit enter/exit/layout.\n        if (!this.targets.has(subject)) this.targets.set(subject, {})\n\n        return this\n    }\n\n    /**\n     * Control this subject's crop (clip + `object-fit: cover` + animated\n     * corners). By default a subject auto-crops only when it actually morphs -\n     * present in both snapshots (a survivor, or an `.add(a, b)` pair). A\n     * fade-only enter/exit has no second box to crop against, so it's left to\n     * the browser default; in particular the `overflow: clip` a crop adds would\n     * otherwise clip a mis-sized enter/exit layer to nothing.\n     *\n     * `.crop(false)` forces the crop off (e.g. a text morph, where\n     * `object-fit: cover` clips glyphs as the box grows); `.crop(true)` forces\n     * it on for a non-morph the default wouldn't otherwise crop.\n     */\n    crop(enabled = true) {\n        this.cropOverride.set(this.currentSubject, enabled)\n\n        return this\n    }\n\n    /**\n     * By default a subject's layer nests under its nearest DOM-ancestor layer\n     * (`view-transition-group: contain`), so the ancestor's clip/transform/opacity\n     * apply to it through the transition - mirroring how the DOM actually paints,\n     * and letting a wrapper crop its child for the whole morph rather than only\n     * once the live DOM takes back over. (Needs a browser that supports nested\n     * view-transition groups; elsewhere it degrades to the flat default.)\n     *\n     * Call `.group(false)` to opt out: the layer stays flat and top-level, so it\n     * animates independently and escapes an ancestor's clip - e.g. an element\n     * that should lift out of a card and fly across, which nesting would clip.\n     */\n    group(enabled = true) {\n        enabled\n            ? this.flatGroups.delete(this.currentSubject)\n            : this.flatGroups.add(this.currentSubject)\n\n        return this\n    }\n\n    /**\n     * Tag this subject's generated layers with a `view-transition-class`, so\n     * they can be targeted from CSS - `::view-transition-group(.name)`,\n     * `::view-transition-old/new(.name)`, `::view-transition-image-pair(.name)`\n     * - without the opaque generated `view-transition-name`. Because `.add()`\n     * can match many elements, a shared class targets them all at once (and,\n     * for a pair, both ends). The escape hatch for z-index / custom keyframes\n     * on a morph layer.\n     */\n    class(name: string) {\n        this.classNames.set(this.currentSubject, name)\n\n        return this\n    }\n\n    /**\n     * Set the transition for this subject's morph. The morph is enabled\n     * automatically by `.add()`; this just customises its timing (duration,\n     * easing, a `delay`/`stagger`, …). On the implicit `root` subject it also\n     * opts the page into the transition (the root crossfade).\n     */\n    layout(options: AnimationOptions = {}) {\n        this.updateTarget(\"layout\", {}, options)\n\n        return this\n    }\n\n    enter(keyframes: DOMKeyframesDefinition, options?: AnimationOptions) {\n        this.updateTarget(\"enter\", keyframes, options)\n\n        return this\n    }\n\n    exit(keyframes: DOMKeyframesDefinition, options?: AnimationOptions) {\n        this.updateTarget(\"exit\", keyframes, options)\n\n        return this\n    }\n\n    /**\n     * Animate the new view directly, whether the element is appearing or\n     * persisting (unlike `.enter()`, which only fires for a pure newcomer).\n     * Pair with `.old()` for a crossfade or slide-through.\n     */\n    new(keyframes: DOMKeyframesDefinition, options?: AnimationOptions) {\n        this.updateTarget(\"new\", keyframes, options)\n\n        return this\n    }\n\n    /**\n     * Animate the old view directly, whether the element is leaving or\n     * persisting (unlike `.exit()`, which only fires for a pure leaver).\n     */\n    old(keyframes: DOMKeyframesDefinition, options?: AnimationOptions) {\n        this.updateTarget(\"old\", keyframes, options)\n\n        return this\n    }\n\n    updateTarget(\n        target: \"enter\" | \"exit\" | \"layout\" | \"new\" | \"old\",\n        keyframes: DOMKeyframesDefinition,\n        options: AnimationOptions = {}\n    ) {\n        const { currentSubject, targets } = this\n\n        if (!targets.has(currentSubject)) {\n            targets.set(currentSubject, {})\n        }\n\n        const targetData = targets.get(currentSubject)!\n\n        targetData[target] = { keyframes, options }\n    }\n\n    then(resolve: () => void, reject?: () => void) {\n        return this.readyPromise.then(resolve, reject)\n    }\n}\n\nexport function animateView(\n    update: () => void | Promise<void>,\n    options: ViewTransitionOptions = {}\n) {\n    return new ViewTransitionBuilder(update, options)\n}\n","import { Axis, AxisDelta, Box, Delta } from \"motion-utils\"\n\nexport const createAxisDelta = (): AxisDelta => ({\n    translate: 0,\n    scale: 1,\n    origin: 0,\n    originPoint: 0,\n})\n\nexport const createDelta = (): Delta => ({\n    x: createAxisDelta(),\n    y: createAxisDelta(),\n})\n\nexport const createAxis = (): Axis => ({ min: 0, max: 0 })\n\nexport const createBox = (): Box => ({\n    x: createAxis(),\n    y: createAxis(),\n})\n","import type { VisualElement } from \"./VisualElement\"\n\nexport const visualElementStore = new WeakMap<any, VisualElement>()\n","import type { LegacyAnimationControls } from \"../../node/types\"\n\nexport function isAnimationControls(v?: unknown): v is LegacyAnimationControls {\n    return (\n        v !== null &&\n        typeof v === \"object\" &&\n        typeof (v as LegacyAnimationControls).start === \"function\"\n    )\n}\n","/**\n * Decides if the supplied variable is variant label\n */\nexport function isVariantLabel(v: unknown): v is string | string[] {\n    return typeof v === \"string\" || Array.isArray(v)\n}\n","import type { AnimationType } from \"../types\"\n\nexport const variantPriorityOrder: AnimationType[] = [\n    \"animate\",\n    \"whileInView\",\n    \"whileFocus\",\n    \"whileHover\",\n    \"whileTap\",\n    \"whileDrag\",\n    \"exit\",\n]\n\nexport const variantProps = [\"initial\", ...variantPriorityOrder]\n","import type { MotionNodeOptions } from \"../../node/types\"\nimport { isAnimationControls } from \"./is-animation-controls\"\nimport { isVariantLabel } from \"./is-variant-label\"\nimport { variantProps } from \"./variant-props\"\n\nexport function isControllingVariants(props: MotionNodeOptions) {\n    return (\n        isAnimationControls(props.animate) ||\n        variantProps.some((name) =>\n            isVariantLabel(props[name as keyof typeof props])\n        )\n    )\n}\n\nexport function isVariantNode(props: MotionNodeOptions) {\n    return Boolean(isControllingVariants(props) || props.variants)\n}\n","import { motionValue } from \"../../value\"\nimport { isMotionValue } from \"../../value/utils/is-motion-value\"\n\ntype MotionStyleLike = Record<string, any>\n\n/**\n * Updates motion values from props changes.\n * Uses `any` type for element to avoid circular dependencies with VisualElement.\n */\nexport function updateMotionValuesFromProps(\n    element: any,\n    next: MotionStyleLike,\n    prev: MotionStyleLike\n) {\n    for (const key in next) {\n        const nextValue = next[key]\n        const prevValue = prev[key]\n\n        if (isMotionValue(nextValue)) {\n            /**\n             * If this is a motion value found in props or style, we want to add it\n             * to our visual element's motion value map.\n             */\n            element.addValue(key, nextValue)\n        } else if (isMotionValue(prevValue)) {\n            /**\n             * If we're swapping from a motion value to a static value,\n             * create a new motion value from that\n             */\n            element.addValue(key, motionValue(nextValue, { owner: element }))\n        } else if (prevValue !== nextValue) {\n            /**\n             * If this is a flat value that has changed, update the motion value\n             * or create one if it doesn't exist. We only want to do this if we're\n             * not handling the value with our animation state.\n             */\n            if (element.hasValue(key)) {\n                const existingValue = element.getValue(key)!\n\n                if (existingValue.liveStyle === true) {\n                    existingValue.jump(nextValue)\n                } else if (!existingValue.hasAnimated) {\n                    existingValue.set(nextValue)\n                }\n            } else {\n                const latestValue = element.getStaticValue(key)\n                element.addValue(\n                    key,\n                    motionValue(\n                        latestValue !== undefined ? latestValue : nextValue,\n                        { owner: element }\n                    )\n                )\n            }\n        }\n    }\n\n    // Handle removed values\n    for (const key in prev) {\n        if (next[key] === undefined) element.removeValue(key)\n    }\n\n    return next\n}\n","interface ReducedMotionState {\n    current: boolean | null\n}\n\n// Does this device prefer reduced motion? Returns `null` server-side.\nexport const prefersReducedMotion: ReducedMotionState = { current: null }\n\nexport const hasReducedMotionListener = { current: false }\n","import { hasReducedMotionListener, prefersReducedMotion } from \"./state\"\n\nconst isBrowser = typeof window !== \"undefined\"\n\nexport function initPrefersReducedMotion() {\n    hasReducedMotionListener.current = true\n    if (!isBrowser) return\n\n    if (window.matchMedia) {\n        const motionMediaQuery = window.matchMedia(\"(prefers-reduced-motion)\")\n\n        const setReducedMotionPreferences = () =>\n            (prefersReducedMotion.current = motionMediaQuery.matches)\n\n        motionMediaQuery.addEventListener(\"change\", setReducedMotionPreferences)\n\n        setReducedMotionPreferences()\n    } else {\n        prefersReducedMotion.current = false\n    }\n}\n\nexport { prefersReducedMotion, hasReducedMotionListener }\n","import {\n    Box,\n    isNumericalString,\n    isZeroValueString,\n    secondsToMilliseconds,\n    SubscriptionManager,\n    warnOnce,\n} from \"motion-utils\"\nimport { KeyframeResolver } from \"../animation/keyframes/KeyframesResolver\"\nimport { NativeAnimation } from \"../animation/NativeAnimation\"\nimport type { AnyResolvedKeyframe } from \"../animation/types\"\nimport { acceleratedValues } from \"../animation/waapi/utils/accelerated-values\"\nimport { cancelFrame, frame } from \"../frameloop\"\nimport { microtask } from \"../frameloop/microtask\"\nimport { time } from \"../frameloop/sync-time\"\nimport type { MotionNodeOptions } from \"../node/types\"\nimport { createBox } from \"../projection/geometry/models\"\nimport { motionValue, MotionValue } from \"../value\"\nimport { complex } from \"../value/types/complex\"\nimport { getAnimatableNone } from \"../value/types/utils/animatable-none\"\nimport { findValueType } from \"../value/types/utils/find\"\nimport { isMotionValue } from \"../value/utils/is-motion-value\"\nimport { Feature } from \"./Feature\"\nimport { visualElementStore } from \"./store\"\nimport {\n    FeatureDefinitions,\n    MotionConfigContextProps,\n    PresenceContextProps,\n    ReducedMotionConfig,\n    ResolvedValues,\n    VisualElementEventCallbacks,\n    VisualElementOptions,\n} from \"./types\"\nimport { AnimationState } from \"./utils/animation-state\"\nimport {\n    isControllingVariants as checkIsControllingVariants,\n    isVariantNode as checkIsVariantNode,\n} from \"./utils/is-controlling-variants\"\nimport { transformProps } from \"./utils/keys-transform\"\nimport { updateMotionValuesFromProps } from \"./utils/motion-values\"\nimport {\n    hasReducedMotionListener,\n    initPrefersReducedMotion,\n    prefersReducedMotion,\n} from \"./utils/reduced-motion\"\nimport { resolveVariantFromProps } from \"./utils/resolve-variants\"\n\nconst propEventHandlers = [\n    \"AnimationStart\",\n    \"AnimationComplete\",\n    \"Update\",\n    \"BeforeLayoutMeasure\",\n    \"LayoutMeasure\",\n    \"LayoutAnimationStart\",\n    \"LayoutAnimationComplete\",\n] as const\n\n/**\n * Static feature definitions - can be injected by framework layer\n */\nlet featureDefinitions: Partial<FeatureDefinitions> = {}\n\n/**\n * Set feature definitions for all VisualElements.\n * This should be called by the framework layer (e.g., framer-motion) during initialization.\n */\nexport function setFeatureDefinitions(\n    definitions: Partial<FeatureDefinitions>\n) {\n    featureDefinitions = definitions\n}\n\n/**\n * Get the current feature definitions\n */\nexport function getFeatureDefinitions(): Partial<FeatureDefinitions> {\n    return featureDefinitions\n}\n\n/**\n * Motion style type - a subset of CSS properties that can contain motion values\n */\nexport type MotionStyle = {\n    [K: string]: AnyResolvedKeyframe | MotionValue | undefined\n}\n\n/**\n * A VisualElement is an imperative abstraction around UI elements such as\n * HTMLElement, SVGElement, Three.Object3D etc.\n */\nexport abstract class VisualElement<\n    Instance = unknown,\n    RenderState = unknown,\n    Options extends {} = {}\n> {\n    /**\n     * VisualElements are arranged in trees mirroring that of the React tree.\n     * Each type of VisualElement has a unique name, to detect when we're crossing\n     * type boundaries within that tree.\n     */\n    abstract type: string\n\n    /**\n     * An `Array.sort` compatible function that will compare two Instances and\n     * compare their respective positions within the tree.\n     */\n    abstract sortInstanceNodePosition(a: Instance, b: Instance): number\n\n    /**\n     * Measure the viewport-relative bounding box of the Instance.\n     */\n    abstract measureInstanceViewportBox(\n        instance: Instance,\n        props: MotionNodeOptions & Partial<MotionConfigContextProps>\n    ): Box\n\n    /**\n     * When a value has been removed from all animation props we need to\n     * pick a target to animate back to. For instance, for HTMLElements\n     * we can look in the style prop.\n     */\n    abstract getBaseTargetFromProps(\n        props: MotionNodeOptions,\n        key: string\n    ): AnyResolvedKeyframe | undefined | MotionValue\n\n    /**\n     * When we first animate to a value we need to animate it *from* a value.\n     * Often this have been specified via the initial prop but it might be\n     * that the value needs to be read from the Instance.\n     */\n    abstract readValueFromInstance(\n        instance: Instance,\n        key: string,\n        options: Options\n    ): AnyResolvedKeyframe | null | undefined\n\n    /**\n     * When a value has been removed from the VisualElement we use this to remove\n     * it from the inherting class' unique render state.\n     */\n    abstract removeValueFromRenderState(\n        key: string,\n        renderState: RenderState\n    ): void\n\n    /**\n     * Run before a React or VisualElement render, builds the latest motion\n     * values into an Instance-specific format. For example, HTMLVisualElement\n     * will use this step to build `style` and `var` values.\n     */\n    abstract build(\n        renderState: RenderState,\n        latestValues: ResolvedValues,\n        props: MotionNodeOptions\n    ): void\n\n    /**\n     * Apply the built values to the Instance. For example, HTMLElements will have\n     * styles applied via `setProperty` and the style attribute, whereas SVGElements\n     * will have values applied to attributes.\n     */\n    abstract renderInstance(\n        instance: Instance,\n        renderState: RenderState,\n        styleProp?: MotionStyle,\n        projection?: any\n    ): void\n\n    /**\n     * This method is called when a transform property is bound to a motion value.\n     * It's currently used to measure SVG elements when a new transform property is bound.\n     */\n    onBindTransform?(): void\n\n    /**\n     * If the component child is provided as a motion value, handle subscriptions\n     * with the renderer-specific VisualElement.\n     */\n    handleChildMotionValue?(): void\n\n    /**\n     * This method takes React props and returns found MotionValues. For example, HTML\n     * MotionValues will be found within the style prop, whereas for Three.js within attribute arrays.\n     *\n     * This isn't an abstract method as it needs calling in the constructor, but it is\n     * intended to be one.\n     */\n    scrapeMotionValuesFromProps(\n        _props: MotionNodeOptions,\n        _prevProps: MotionNodeOptions,\n        _visualElement: VisualElement\n    ): {\n        [key: string]: MotionValue | AnyResolvedKeyframe\n    } {\n        return {}\n    }\n\n    /**\n     * A reference to the current underlying Instance, e.g. a HTMLElement\n     * or Three.Mesh etc.\n     */\n    current: Instance | null = null\n\n    /**\n     * A reference to the parent VisualElement (if exists).\n     */\n    parent: VisualElement | undefined\n\n    /**\n     * A set containing references to this VisualElement's children.\n     */\n    children = new Set<VisualElement>()\n\n    /**\n     * A set containing the latest children of this VisualElement. This is flushed\n     * at the start of every commit. We use it to calculate the stagger delay\n     * for newly-added children.\n     */\n    enteringChildren?: Set<VisualElement>\n\n    /**\n     * The depth of this VisualElement within the overall VisualElement tree.\n     */\n    depth: number\n\n    /**\n     * The current render state of this VisualElement. Defined by inherting VisualElements.\n     */\n    renderState: RenderState\n\n    /**\n     * An object containing the latest static values for each of this VisualElement's\n     * MotionValues.\n     */\n    latestValues: ResolvedValues\n\n    /**\n     * Determine what role this visual element should take in the variant tree.\n     */\n    isVariantNode: boolean = false\n    isControllingVariants: boolean = false\n\n    /**\n     * If this component is part of the variant tree, it should track\n     * any children that are also part of the tree. This is essentially\n     * a shadow tree to simplify logic around how to stagger over children.\n     */\n    variantChildren?: Set<VisualElement>\n\n    /**\n     * Decides whether this VisualElement should animate in reduced motion\n     * mode.\n     *\n     * TODO: This is currently set on every individual VisualElement but feels\n     * like it could be set globally.\n     */\n    shouldReduceMotion: boolean | null = null\n\n    /**\n     * Decides whether animations should be skipped for this VisualElement.\n     * Useful for E2E tests and visual regression testing.\n     */\n    shouldSkipAnimations: boolean = false\n\n    /**\n     * Normally, if a component is controlled by a parent's variants, it can\n     * rely on that ancestor to trigger animations further down the tree.\n     * However, if a component is created after its parent is mounted, the parent\n     * won't trigger that mount animation so the child needs to.\n     *\n     * TODO: This might be better replaced with a method isParentMounted\n     */\n    manuallyAnimateOnMount: boolean\n\n    /**\n     * This can be set by AnimatePresence to force components that mount\n     * at the same time as it to mount as if they have initial={false} set.\n     */\n    blockInitialAnimation: boolean\n\n    /**\n     * A reference to this VisualElement's projection node, used in layout animations.\n     */\n    projection?: any\n\n    /**\n     * A map of all motion values attached to this visual element. Motion\n     * values are source of truth for any given animated value. A motion\n     * value might be provided externally by the component via props.\n     */\n    values = new Map<string, MotionValue>()\n\n    /**\n     * The AnimationState, this is hydrated by the animation Feature.\n     */\n    animationState?: AnimationState\n\n    KeyframeResolver = KeyframeResolver\n\n    /**\n     * The options used to create this VisualElement. The Options type is defined\n     * by the inheriting VisualElement and is passed straight through to the render functions.\n     */\n    readonly options: Options\n\n    /**\n     * A reference to the latest props provided to the VisualElement's host React component.\n     */\n    props: MotionNodeOptions\n    prevProps?: MotionNodeOptions\n\n    presenceContext: PresenceContextProps | null\n    prevPresenceContext?: PresenceContextProps | null\n\n    /**\n     * Cleanup functions for active features (hover/tap/exit etc)\n     */\n    private features: {\n        [K in keyof FeatureDefinitions]?: Feature<Instance>\n    } = {}\n\n    /**\n     * A map of every subscription that binds the provided or generated\n     * motion values onChange listeners to this visual element.\n     */\n    private valueSubscriptions = new Map<string, VoidFunction>()\n\n    /**\n     * A reference to the ReducedMotionConfig passed to the VisualElement's host React component.\n     */\n    private reducedMotionConfig: ReducedMotionConfig | undefined\n\n    /**\n     * A reference to the skipAnimations config passed to the VisualElement's host React component.\n     */\n    private skipAnimationsConfig: boolean | undefined\n\n    /**\n     * On mount, this will be hydrated with a callback to disconnect\n     * this visual element from its parent on unmount.\n     */\n    private removeFromVariantTree: undefined | VoidFunction\n\n    /**\n     * A reference to the previously-provided motion values as returned\n     * from scrapeMotionValuesFromProps. We use the keys in here to determine\n     * if any motion values need to be removed after props are updated.\n     */\n    private prevMotionValues: MotionStyle = {}\n\n    /**\n     * When values are removed from all animation props we need to search\n     * for a fallback value to animate to. These values are tracked in baseTarget.\n     */\n    private baseTarget: ResolvedValues\n\n    /**\n     * Create an object of the values we initially animated from (if initial prop present).\n     */\n    private initialValues: ResolvedValues\n\n    /**\n     * Track whether this element has been mounted before, to detect\n     * remounts after Suspense unmount/remount cycles.\n     */\n    private hasBeenMounted = false\n\n    /**\n     * An object containing a SubscriptionManager for each active event.\n     */\n    private events: {\n        [key: string]: SubscriptionManager<any>\n    } = {}\n\n    /**\n     * An object containing an unsubscribe function for each prop event subscription.\n     * For example, every \"Update\" event can have multiple subscribers via\n     * VisualElement.on(), but only one of those can be defined via the onUpdate prop.\n     */\n    private propEventSubscriptions: {\n        [key: string]: VoidFunction\n    } = {}\n\n    constructor(\n        {\n            parent,\n            props,\n            presenceContext,\n            reducedMotionConfig,\n            skipAnimations,\n            blockInitialAnimation,\n            visualState,\n        }: VisualElementOptions<Instance, RenderState>,\n        options: Options = {} as any\n    ) {\n        const { latestValues, renderState } = visualState\n        this.latestValues = latestValues\n        this.baseTarget = { ...latestValues }\n        this.initialValues = props.initial ? { ...latestValues } : {}\n        this.renderState = renderState\n        this.parent = parent\n        this.props = props\n        this.presenceContext = presenceContext\n        this.depth = parent ? parent.depth + 1 : 0\n        this.reducedMotionConfig = reducedMotionConfig\n        this.skipAnimationsConfig = skipAnimations\n        this.options = options\n        this.blockInitialAnimation = Boolean(blockInitialAnimation)\n\n        this.isControllingVariants = checkIsControllingVariants(props)\n        this.isVariantNode = checkIsVariantNode(props)\n        if (this.isVariantNode) {\n            this.variantChildren = new Set()\n        }\n\n        this.manuallyAnimateOnMount = Boolean(parent && parent.current)\n\n        /**\n         * Any motion values that are provided to the element when created\n         * aren't yet bound to the element, as this would technically be impure.\n         * However, we iterate through the motion values and set them to the\n         * initial values for this component.\n         *\n         * TODO: This is impure and we should look at changing this to run on mount.\n         * Doing so will break some tests but this isn't necessarily a breaking change,\n         * more a reflection of the test.\n         */\n        const { willChange, ...initialMotionValues } =\n            this.scrapeMotionValuesFromProps(props, {}, this)\n\n        for (const key in initialMotionValues) {\n            const value = initialMotionValues[key]\n\n            if (latestValues[key] !== undefined && isMotionValue(value)) {\n                value.set(latestValues[key])\n            }\n        }\n    }\n\n    mount(instance: Instance) {\n        /**\n         * If this element has been mounted before (e.g. after a Suspense\n         * unmount/remount), reset motion values to their initial state\n         * so animations replay correctly from initial → animate.\n         */\n        if (this.hasBeenMounted) {\n            for (const key in this.initialValues) {\n                this.values.get(key)?.jump(this.initialValues[key])\n                this.latestValues[key] = this.initialValues[key]\n            }\n        }\n\n        this.current = instance\n\n        visualElementStore.set(instance, this)\n\n        if (this.projection && !this.projection.instance) {\n            this.projection.mount(instance)\n        }\n\n        if (this.parent && this.isVariantNode && !this.isControllingVariants) {\n            this.removeFromVariantTree = this.parent.addVariantChild(this)\n        }\n\n        this.values.forEach((value, key) => this.bindToMotionValue(key, value))\n\n        /**\n         * Determine reduced motion preference. Only initialize the matchMedia\n         * listener if we actually need the dynamic value (i.e., when config\n         * is neither \"never\" nor \"always\").\n         */\n        if (this.reducedMotionConfig === \"never\") {\n            this.shouldReduceMotion = false\n        } else if (this.reducedMotionConfig === \"always\") {\n            this.shouldReduceMotion = true\n        } else {\n            if (!hasReducedMotionListener.current) {\n                initPrefersReducedMotion()\n            }\n            this.shouldReduceMotion = prefersReducedMotion.current\n        }\n\n        if (process.env.NODE_ENV !== \"production\") {\n            warnOnce(\n                this.shouldReduceMotion !== true,\n                \"You have Reduced Motion enabled on your device. Animations may not appear as expected.\",\n                \"reduced-motion-disabled\"\n            )\n        }\n\n        /**\n         * Set whether animations should be skipped based on the config.\n         */\n        this.shouldSkipAnimations = this.skipAnimationsConfig ?? false\n\n        this.parent?.addChild(this)\n\n        this.update(this.props, this.presenceContext)\n\n        this.hasBeenMounted = true\n    }\n\n    unmount() {\n        this.projection && this.projection.unmount()\n        cancelFrame(this.notifyUpdate)\n        cancelFrame(this.render)\n        this.valueSubscriptions.forEach((remove) => remove())\n        this.valueSubscriptions.clear()\n        this.removeFromVariantTree && this.removeFromVariantTree()\n        this.parent?.removeChild(this)\n\n        for (const key in this.events) {\n            this.events[key].clear()\n        }\n\n        for (const key in this.features) {\n            const feature = this.features[key as keyof typeof this.features]\n            if (feature) {\n                feature.unmount()\n                feature.isMounted = false\n            }\n        }\n        this.current = null\n    }\n\n    addChild(child: VisualElement) {\n        this.children.add(child)\n        this.enteringChildren ??= new Set()\n        this.enteringChildren.add(child)\n    }\n\n    removeChild(child: VisualElement) {\n        this.children.delete(child)\n        this.enteringChildren && this.enteringChildren.delete(child)\n    }\n\n    private bindToMotionValue(key: string, value: MotionValue) {\n        if (this.valueSubscriptions.has(key)) {\n            this.valueSubscriptions.get(key)!()\n        }\n\n        if (\n            value.accelerate &&\n            acceleratedValues.has(key) &&\n            this.current instanceof HTMLElement\n        ) {\n            const { factory, keyframes, times, ease, duration } =\n                value.accelerate\n\n            const animation = new NativeAnimation({\n                element: this.current,\n                name: key,\n                keyframes,\n                times,\n                ease,\n                duration: secondsToMilliseconds(duration),\n            })\n\n            const cleanup = factory(animation)\n\n            this.valueSubscriptions.set(key, () => {\n                cleanup()\n                animation.cancel()\n            })\n            return\n        }\n\n        const valueIsTransform = transformProps.has(key)\n\n        if (valueIsTransform && this.onBindTransform) {\n            this.onBindTransform()\n        }\n\n        const removeOnChange = value.on(\n            \"change\",\n            (latestValue: AnyResolvedKeyframe) => {\n                this.latestValues[key] = latestValue\n\n                this.props.onUpdate && frame.preRender(this.notifyUpdate)\n\n                if (valueIsTransform && this.projection) {\n                    this.projection.isTransformDirty = true\n                }\n\n                this.scheduleRender()\n            }\n        )\n\n        let removeSyncCheck: VoidFunction | void\n        if (\n            typeof window !== \"undefined\" &&\n            (window as any).MotionCheckAppearSync\n        ) {\n            removeSyncCheck = (window as any).MotionCheckAppearSync(\n                this,\n                key,\n                value\n            )\n        }\n\n        this.valueSubscriptions.set(key, () => {\n            removeOnChange()\n            if (removeSyncCheck) removeSyncCheck()\n            // Defer to MotionValue.on(\"change\") auto-stop so React 19 remounts\n            // can resubscribe before the animation is cancelled (#3315).\n        })\n    }\n\n    sortNodePosition(other: VisualElement<Instance>) {\n        /**\n         * If these nodes aren't even of the same type we can't compare their depth.\n         */\n        if (\n            !this.current ||\n            !this.sortInstanceNodePosition ||\n            this.type !== other.type\n        ) {\n            return 0\n        }\n\n        return this.sortInstanceNodePosition(\n            this.current as Instance,\n            other.current as Instance\n        )\n    }\n\n    updateFeatures() {\n        let key: keyof typeof featureDefinitions = \"animation\"\n\n        for (key in featureDefinitions) {\n            const featureDefinition = featureDefinitions[key]\n\n            if (!featureDefinition) continue\n\n            const { isEnabled, Feature: FeatureConstructor } = featureDefinition\n\n            /**\n             * If this feature is enabled but not active, make a new instance.\n             */\n            if (\n                !this.features[key] &&\n                FeatureConstructor &&\n                isEnabled(this.props)\n            ) {\n                this.features[key] = new FeatureConstructor(this) as any\n            }\n\n            /**\n             * If we have a feature, mount or update it.\n             */\n            if (this.features[key]) {\n                const feature = this.features[key]!\n                if (feature.isMounted) {\n                    feature.update()\n                } else {\n                    feature.mount()\n                    feature.isMounted = true\n                }\n            }\n        }\n    }\n\n    notifyUpdate = () => this.notify(\"Update\", this.latestValues)\n\n    triggerBuild() {\n        this.build(this.renderState, this.latestValues, this.props)\n    }\n\n    render = () => {\n        if (!this.current) return\n        this.triggerBuild()\n        this.renderInstance(\n            this.current,\n            this.renderState,\n            (this.props as any).style,\n            this.projection\n        )\n    }\n\n    private renderScheduledAt = 0.0\n    scheduleRender = () => {\n        const now = time.now()\n        if (this.renderScheduledAt < now) {\n            this.renderScheduledAt = now\n            frame.render(this.render, false, true)\n        }\n    }\n\n    /**\n     * Measure the current viewport box with or without transforms.\n     * Only measures axis-aligned boxes, rotate and skew must be manually\n     * removed with a re-render to work.\n     */\n    measureViewportBox() {\n        return this.current\n            ? this.measureInstanceViewportBox(this.current, this.props)\n            : createBox()\n    }\n\n    getStaticValue(key: string) {\n        return this.latestValues[key]\n    }\n\n    setStaticValue(key: string, value: AnyResolvedKeyframe) {\n        this.latestValues[key] = value\n    }\n\n    /**\n     * Update the provided props. Ensure any newly-added motion values are\n     * added to our map, old ones removed, and listeners updated.\n     */\n    update(\n        props: MotionNodeOptions,\n        presenceContext: PresenceContextProps | null\n    ) {\n        if (props.transformTemplate || this.props.transformTemplate) {\n            this.scheduleRender()\n        }\n\n        this.prevProps = this.props\n        this.props = props\n\n        this.prevPresenceContext = this.presenceContext\n        this.presenceContext = presenceContext\n\n        /**\n         * Update prop event handlers ie onAnimationStart, onAnimationComplete\n         */\n        for (let i = 0; i < propEventHandlers.length; i++) {\n            const key = propEventHandlers[i]\n            if (this.propEventSubscriptions[key]) {\n                this.propEventSubscriptions[key]()\n                delete this.propEventSubscriptions[key]\n            }\n\n            const listenerName = (\"on\" + key) as keyof typeof props\n            const listener = props[listenerName]\n            if (listener) {\n                this.propEventSubscriptions[key] = this.on(key as any, listener)\n            }\n        }\n\n        this.prevMotionValues = updateMotionValuesFromProps(\n            this,\n            this.scrapeMotionValuesFromProps(props, this.prevProps || {}, this),\n            this.prevMotionValues\n        )\n\n        if (this.handleChildMotionValue) {\n            this.handleChildMotionValue()\n        }\n    }\n\n    getProps() {\n        return this.props\n    }\n\n    /**\n     * Returns the variant definition with a given name.\n     */\n    getVariant(name: string) {\n        return this.props.variants ? this.props.variants[name] : undefined\n    }\n\n    /**\n     * Returns the defined default transition on this component.\n     */\n    getDefaultTransition() {\n        return this.props.transition\n    }\n\n    getTransformPagePoint() {\n        return (this.props as any).transformPagePoint\n    }\n\n    getClosestVariantNode(): VisualElement | undefined {\n        return this.isVariantNode\n            ? this\n            : this.parent\n            ? this.parent.getClosestVariantNode()\n            : undefined\n    }\n\n    /**\n     * Add a child visual element to our set of children.\n     */\n    addVariantChild(child: VisualElement) {\n        const closestVariantNode = this.getClosestVariantNode()\n        if (closestVariantNode) {\n            closestVariantNode.variantChildren &&\n                closestVariantNode.variantChildren.add(child)\n            return () => closestVariantNode.variantChildren!.delete(child)\n        }\n    }\n\n    /**\n     * Add a motion value and bind it to this visual element.\n     */\n    addValue(key: string, value: MotionValue) {\n        // Remove existing value if it exists\n        const existingValue = this.values.get(key)\n\n        if (value !== existingValue) {\n            if (existingValue) this.removeValue(key)\n            this.bindToMotionValue(key, value)\n            this.values.set(key, value)\n            this.latestValues[key] = value.get()\n        }\n    }\n\n    /**\n     * Remove a motion value and unbind any active subscriptions.\n     */\n    removeValue(key: string) {\n        this.values.delete(key)\n        const unsubscribe = this.valueSubscriptions.get(key)\n        if (unsubscribe) {\n            unsubscribe()\n            this.valueSubscriptions.delete(key)\n        }\n        delete this.latestValues[key]\n        this.removeValueFromRenderState(key, this.renderState)\n    }\n\n    /**\n     * Check whether we have a motion value for this key\n     */\n    hasValue(key: string) {\n        return this.values.has(key)\n    }\n\n    /**\n     * Get a motion value for this key. If called with a default\n     * value, we'll create one if none exists.\n     */\n    getValue(key: string): MotionValue | undefined\n    getValue(key: string, defaultValue: AnyResolvedKeyframe | null): MotionValue\n    getValue(\n        key: string,\n        defaultValue?: AnyResolvedKeyframe | null\n    ): MotionValue | undefined {\n        if (this.props.values && this.props.values[key]) {\n            return this.props.values[key]\n        }\n\n        let value = this.values.get(key)\n\n        if (value === undefined && defaultValue !== undefined) {\n            value = motionValue(\n                defaultValue === null ? undefined : defaultValue,\n                { owner: this }\n            )\n            this.addValue(key, value)\n        }\n\n        return value\n    }\n\n    /**\n     * If we're trying to animate to a previously unencountered value,\n     * we need to check for it in our state and as a last resort read it\n     * directly from the instance (which might have performance implications).\n     */\n    readValue(key: string, target?: AnyResolvedKeyframe | null) {\n        let value =\n            this.latestValues[key] !== undefined || !this.current\n                ? this.latestValues[key]\n                : this.getBaseTargetFromProps(this.props, key) ??\n                  this.readValueFromInstance(this.current, key, this.options)\n\n        if (value !== undefined && value !== null) {\n            if (\n                typeof value === \"string\" &&\n                (isNumericalString(value) || isZeroValueString(value))\n            ) {\n                // If this is a number read as a string, ie \"0\" or \"200\", convert it to a number\n                value = parseFloat(value)\n            } else if (!findValueType(value) && complex.test(target)) {\n                value = getAnimatableNone(key, target as string)\n            }\n\n            this.setBaseTarget(key, isMotionValue(value) ? value.get() : value)\n        }\n\n        return isMotionValue(value) ? value.get() : value\n    }\n\n    /**\n     * Set the base target to later animate back to. This is currently\n     * only hydrated on creation and when we first read a value.\n     */\n    setBaseTarget(key: string, value: AnyResolvedKeyframe) {\n        this.baseTarget[key] = value\n    }\n\n    /**\n     * Find the base target for a value thats been removed from all animation\n     * props.\n     */\n    getBaseTarget(key: string): ResolvedValues[string] | undefined | null {\n        const { initial } = this.props\n\n        let valueFromInitial: ResolvedValues[string] | undefined | null\n\n        if (typeof initial === \"string\" || typeof initial === \"object\") {\n            const variant = resolveVariantFromProps(\n                this.props,\n                initial as any,\n                this.presenceContext?.custom\n            )\n            if (variant) {\n                valueFromInitial = variant[\n                    key as keyof typeof variant\n                ] as string\n            }\n        }\n\n        /**\n         * If this value still exists in the current initial variant, read that.\n         */\n        if (initial && valueFromInitial !== undefined) {\n            return valueFromInitial\n        }\n\n        /**\n         * Alternatively, if this VisualElement config has defined a getBaseTarget\n         * so we can read the value from an alternative source, try that.\n         */\n        const target = this.getBaseTargetFromProps(this.props, key)\n        if (target !== undefined && !isMotionValue(target)) return target\n\n        /**\n         * If the value was initially defined on initial, but it doesn't any more,\n         * return undefined. Otherwise return the value as initially read from the DOM.\n         */\n        return this.initialValues[key] !== undefined &&\n            valueFromInitial === undefined\n            ? undefined\n            : this.baseTarget[key]\n    }\n\n    on<EventName extends keyof VisualElementEventCallbacks>(\n        eventName: EventName,\n        callback: VisualElementEventCallbacks[EventName]\n    ) {\n        if (!this.events[eventName]) {\n            this.events[eventName] = new SubscriptionManager()\n        }\n\n        return this.events[eventName].add(callback)\n    }\n\n    notify<EventName extends keyof VisualElementEventCallbacks>(\n        eventName: EventName,\n        ...args: any\n    ) {\n        if (this.events[eventName]) {\n            this.events[eventName].notify(...args)\n        }\n    }\n\n    scheduleRenderMicrotask() {\n        microtask.render(this.render)\n    }\n}\n","import { isMotionValue } from \"../../value/utils/is-motion-value\"\nimport type { MotionValue } from \"../../value\"\nimport type { AnyResolvedKeyframe } from \"../../animation/types\"\nimport { DOMKeyframesResolver } from \"../../animation/keyframes/DOMKeyframesResolver\"\nimport type { MotionNodeOptions } from \"../../node/types\"\nimport type { DOMVisualElementOptions } from \"./types\"\nimport type { HTMLRenderState } from \"../html/types\"\nimport { VisualElement, MotionStyle } from \"../VisualElement\"\n\nexport abstract class DOMVisualElement<\n    Instance extends HTMLElement | SVGElement = HTMLElement,\n    State extends HTMLRenderState = HTMLRenderState,\n    Options extends DOMVisualElementOptions = DOMVisualElementOptions\n> extends VisualElement<Instance, State, Options> {\n    sortInstanceNodePosition(a: Instance, b: Instance): number {\n        /**\n         * compareDocumentPosition returns a bitmask, by using the bitwise &\n         * we're returning true if 2 in that bitmask is set to true. 2 is set\n         * to true if b preceeds a.\n         */\n        return a.compareDocumentPosition(b) & 2 ? 1 : -1\n    }\n\n    getBaseTargetFromProps(\n        props: MotionNodeOptions,\n        key: string\n    ): AnyResolvedKeyframe | MotionValue<any> | undefined {\n        const style = (props as MotionNodeOptions & { style?: MotionStyle }).style\n        return style ? (style[key] as string) : undefined\n    }\n\n    removeValueFromRenderState(\n        key: string,\n        { vars, style }: HTMLRenderState\n    ): void {\n        delete vars[key]\n        delete style[key]\n    }\n\n    KeyframeResolver = DOMKeyframesResolver\n\n    childSubscription?: VoidFunction\n    handleChildMotionValue() {\n        if (this.childSubscription) {\n            this.childSubscription()\n            delete this.childSubscription\n        }\n\n        const { children } = this.props as MotionNodeOptions & { children?: MotionValue | any }\n        if (isMotionValue(children)) {\n            this.childSubscription = children.on(\"change\", (latest) => {\n                if (this.current) {\n                    this.current.textContent = `${latest}`\n                }\n            })\n        }\n    }\n}\n","import type { VisualElement } from \"./VisualElement\"\n\n/**\n * Feature base class for extending VisualElement functionality.\n * Features are plugins that can be mounted/unmounted to add behavior\n * like gestures, animations, or layout tracking.\n */\nexport abstract class Feature<T extends any = any> {\n    isMounted = false\n\n    node: VisualElement<T>\n\n    constructor(node: VisualElement<T>) {\n        this.node = node\n    }\n\n    abstract mount(): void\n\n    abstract unmount(): void\n\n    update(): void {}\n}\n","import { BoundingBox, Box, TransformPoint } from \"motion-utils\"\n\n/**\n * Bounding boxes tend to be defined as top, left, right, bottom. For various operations\n * it's easier to consider each axis individually. This function returns a bounding box\n * as a map of single-axis min/max values.\n */\nexport function convertBoundingBoxToBox({\n    top,\n    left,\n    right,\n    bottom,\n}: BoundingBox): Box {\n    return {\n        x: { min: left, max: right },\n        y: { min: top, max: bottom },\n    }\n}\n\nexport function convertBoxToBoundingBox({ x, y }: Box): BoundingBox {\n    return { top: y.min, right: x.max, bottom: y.max, left: x.min }\n}\n\n/**\n * Applies a TransformPoint function to a bounding box. TransformPoint is usually a function\n * provided by Framer to allow measured points to be corrected for device scaling. This is used\n * when measuring DOM elements and DOM event points.\n */\nexport function transformBoxPoints(\n    point: BoundingBox,\n    transformPoint?: TransformPoint\n) {\n    if (!transformPoint) return point\n    const topLeft = transformPoint({ x: point.left, y: point.top })\n    const bottomRight = transformPoint({ x: point.right, y: point.bottom })\n\n    return {\n        top: topLeft.y,\n        left: topLeft.x,\n        bottom: bottomRight.y,\n        right: bottomRight.x,\n    }\n}\n","import { type AnyResolvedKeyframe } from \"../../animation/types\"\nimport { ResolvedValues } from \"../../render/types\"\n\nfunction isIdentityScale(scale: AnyResolvedKeyframe | undefined) {\n    return scale === undefined || scale === 1\n}\n\nexport function hasScale({ scale, scaleX, scaleY }: ResolvedValues) {\n    return (\n        !isIdentityScale(scale) ||\n        !isIdentityScale(scaleX) ||\n        !isIdentityScale(scaleY)\n    )\n}\n\nexport function hasTransform(values: ResolvedValues) {\n    return (\n        hasScale(values) ||\n        has2DTranslate(values) ||\n        values.z ||\n        values.rotate ||\n        values.rotateX ||\n        values.rotateY ||\n        values.skewX ||\n        values.skewY\n    )\n}\n\nexport function has2DTranslate(values: ResolvedValues) {\n    return is2DTranslate(values.x) || is2DTranslate(values.y)\n}\n\nfunction is2DTranslate(value: AnyResolvedKeyframe | undefined) {\n    return value && value !== \"0%\"\n}\n","import { Axis, Box, Delta, Point } from \"motion-utils\"\nimport { mixNumber } from \"../../utils/mix/number\"\nimport { ResolvedValues } from \"../../render/types\"\nimport { hasTransform } from \"../utils/has-transform\"\n\n/**\n * Scales a point based on a factor and an originPoint\n */\nexport function scalePoint(point: number, scale: number, originPoint: number) {\n    const distanceFromOrigin = point - originPoint\n    const scaled = scale * distanceFromOrigin\n    return originPoint + scaled\n}\n\n/**\n * Applies a translate/scale delta to a point\n */\nexport function applyPointDelta(\n    point: number,\n    translate: number,\n    scale: number,\n    originPoint: number,\n    boxScale?: number\n): number {\n    if (boxScale !== undefined) {\n        point = scalePoint(point, boxScale, originPoint)\n    }\n\n    return scalePoint(point, scale, originPoint) + translate\n}\n\n/**\n * Applies a translate/scale delta to an axis\n */\nexport function applyAxisDelta(\n    axis: Axis,\n    translate: number = 0,\n    scale: number = 1,\n    originPoint: number,\n    boxScale?: number\n): void {\n    axis.min = applyPointDelta(\n        axis.min,\n        translate,\n        scale,\n        originPoint,\n        boxScale\n    )\n\n    axis.max = applyPointDelta(\n        axis.max,\n        translate,\n        scale,\n        originPoint,\n        boxScale\n    )\n}\n\n/**\n * Applies a translate/scale delta to a box\n */\nexport function applyBoxDelta(box: Box, { x, y }: Delta): void {\n    applyAxisDelta(box.x, x.translate, x.scale, x.originPoint)\n    applyAxisDelta(box.y, y.translate, y.scale, y.originPoint)\n}\n\nconst TREE_SCALE_SNAP_MIN = 0.999999999999\nconst TREE_SCALE_SNAP_MAX = 1.0000000000001\n\n/**\n * Apply a tree of deltas to a box. We do this to calculate the effect of all the transforms\n * in a tree upon our box before then calculating how to project it into our desired viewport-relative box\n *\n * This is the final nested loop within updateLayoutDelta for future refactoring\n */\nexport function applyTreeDeltas(\n    box: Box,\n    treeScale: Point,\n    treePath: any[],\n    isSharedTransition: boolean = false\n) {\n    const treeLength = treePath.length\n    if (!treeLength) return\n\n    // Reset the treeScale\n    treeScale.x = treeScale.y = 1\n\n    let node: any\n    let delta: Delta | undefined\n\n    for (let i = 0; i < treeLength; i++) {\n        node = treePath[i]\n        delta = node.projectionDelta\n\n        /**\n         * TODO: Prefer to remove this, but currently we have motion components with\n         * display: contents in Framer.\n         */\n        const { visualElement } = node.options\n        if (\n            visualElement &&\n            visualElement.props.style &&\n            visualElement.props.style.display === \"contents\"\n        ) {\n            continue\n        }\n\n        if (\n            isSharedTransition &&\n            node.options.layoutScroll &&\n            node.scroll &&\n            node !== node.root\n        ) {\n            translateAxis(box.x, -node.scroll.offset.x)\n            translateAxis(box.y, -node.scroll.offset.y)\n        }\n\n        if (delta) {\n            // Incoporate each ancestor's scale into a cumulative treeScale for this component\n            treeScale.x *= delta.x.scale\n            treeScale.y *= delta.y.scale\n\n            // Apply each ancestor's calculated delta into this component's recorded layout box\n            applyBoxDelta(box, delta)\n        }\n\n        if (isSharedTransition && hasTransform(node.latestValues)) {\n            transformBox(box, node.latestValues, node.layout?.layoutBox)\n        }\n    }\n\n    /**\n     * Snap tree scale back to 1 if it's within a non-perceivable threshold.\n     * This will help reduce useless scales getting rendered.\n     */\n    if (\n        treeScale.x < TREE_SCALE_SNAP_MAX &&\n        treeScale.x > TREE_SCALE_SNAP_MIN\n    ) {\n        treeScale.x = 1.0\n    }\n    if (\n        treeScale.y < TREE_SCALE_SNAP_MAX &&\n        treeScale.y > TREE_SCALE_SNAP_MIN\n    ) {\n        treeScale.y = 1.0\n    }\n}\n\nexport function translateAxis(axis: Axis, distance: number) {\n    axis.min += distance\n    axis.max += distance\n}\n\n/**\n * Apply a transform to an axis from the latest resolved motion values.\n * This function basically acts as a bridge between a flat motion value map\n * and applyAxisDelta\n */\nexport function transformAxis(\n    axis: Axis,\n    axisTranslate?: number,\n    axisScale?: number,\n    boxScale?: number,\n    axisOrigin: number = 0.5\n): void {\n    const originPoint = mixNumber(axis.min, axis.max, axisOrigin)\n\n    // Apply the axis delta to the final axis\n    applyAxisDelta(axis, axisTranslate, axisScale, originPoint, boxScale)\n}\n\nfunction resolveAxisTranslate(\n    value: number | string | undefined,\n    axis: Axis\n): number | undefined {\n    if (typeof value === \"string\") {\n        return (parseFloat(value) / 100) * (axis.max - axis.min)\n    }\n    return value as number | undefined\n}\n\n/**\n * Apply a transform to a box from the latest resolved motion values.\n */\nexport function transformBox(\n    box: Box,\n    transform: ResolvedValues,\n    sourceBox?: Box\n) {\n    const resolveBox = sourceBox ?? box\n    transformAxis(\n        box.x,\n        resolveAxisTranslate(transform.x, resolveBox.x),\n        transform.scaleX as number,\n        transform.scale as number,\n        transform.originX as number\n    )\n    transformAxis(\n        box.y,\n        resolveAxisTranslate(transform.y, resolveBox.y),\n        transform.scaleY as number,\n        transform.scale as number,\n        transform.originY as number\n    )\n}\n","import { TransformPoint } from \"motion-utils\"\nimport {\n    convertBoundingBoxToBox,\n    transformBoxPoints,\n} from \"../geometry/conversion\"\nimport { translateAxis } from \"../geometry/delta-apply\"\n\nexport function measureViewportBox(\n    instance: HTMLElement,\n    transformPoint?: TransformPoint\n) {\n    return convertBoundingBoxToBox(\n        transformBoxPoints(instance.getBoundingClientRect(), transformPoint)\n    )\n}\n\nexport function measurePageBox(\n    element: HTMLElement,\n    rootProjectionNode: any,\n    transformPagePoint?: TransformPoint\n) {\n    const viewportBox = measureViewportBox(element, transformPagePoint)\n    const { scroll } = rootProjectionNode\n\n    if (scroll) {\n        translateAxis(viewportBox.x, scroll.offset.x)\n        translateAxis(viewportBox.y, scroll.offset.y)\n    }\n\n    return viewportBox\n}\n","import { getValueAsType } from \"../../../value/types/utils/get-as-type\"\nimport { numberValueTypes } from \"../../../value/types/maps/number\"\nimport { transformPropOrder } from \"../../utils/keys-transform\"\nimport { ResolvedValues } from \"../../types\"\nimport { HTMLRenderState } from \"../types\"\nimport type { MotionNodeOptions } from \"../../../node/types\"\n\nconst translateAlias = {\n    x: \"translateX\",\n    y: \"translateY\",\n    z: \"translateZ\",\n    transformPerspective: \"perspective\",\n}\n\nconst numTransforms = transformPropOrder.length\n\n/**\n * Build a CSS transform style from individual x/y/scale etc properties.\n *\n * This outputs with a default order of transforms/scales/rotations, this can be customised by\n * providing a transformTemplate function.\n */\nexport function buildTransform(\n    latestValues: ResolvedValues,\n    transform: HTMLRenderState[\"transform\"],\n    transformTemplate?: MotionNodeOptions[\"transformTemplate\"]\n) {\n    // The transform string we're going to build into.\n    let transformString = \"\"\n    let transformIsDefault = true\n\n    /**\n     * Loop over all possible transforms in order, adding the ones that\n     * are present to the transform string.\n     */\n    for (let i = 0; i < numTransforms; i++) {\n        const key = transformPropOrder[i] as keyof typeof translateAlias\n        const value = latestValues[key]\n\n        if (value === undefined) continue\n\n        let valueIsDefault = true\n        if (typeof value === \"number\") {\n            valueIsDefault = value === (key.startsWith(\"scale\") ? 1 : 0)\n        } else {\n            const parsed = parseFloat(value)\n            valueIsDefault = key.startsWith(\"scale\") ? parsed === 1 : parsed === 0\n        }\n\n        if (!valueIsDefault || transformTemplate) {\n            const valueAsType = getValueAsType(value, numberValueTypes[key])\n\n            if (!valueIsDefault) {\n                transformIsDefault = false\n                const transformName = translateAlias[key] || key\n                transformString += `${transformName}(${valueAsType}) `\n            }\n\n            if (transformTemplate) {\n                transform[key] = valueAsType\n            }\n        }\n    }\n\n    // `pathRotation` composes onto `rotate` as a separate additive term so\n    // the user's `rotate` is never clobbered. Deliberately not a slot in\n    // `transformPropOrder`.\n    const pathRotation = latestValues.pathRotation\n    if (pathRotation) {\n        transformIsDefault = false\n        transformString += `rotate(${getValueAsType(\n            pathRotation,\n            numberValueTypes.pathRotation\n        )}) `\n    }\n\n    transformString = transformString.trim()\n\n    // If we have a custom `transform` template, pass our transform values and\n    // generated transformString to that before returning\n    if (transformTemplate) {\n        transformString = transformTemplate(\n            transform,\n            transformIsDefault ? \"\" : transformString\n        )\n    } else if (transformIsDefault) {\n        transformString = \"none\"\n    }\n\n    return transformString\n}\n","import { getValueAsType } from \"../../../value/types/utils/get-as-type\"\nimport { numberValueTypes } from \"../../../value/types/maps/number\"\nimport { transformProps } from \"../../utils/keys-transform\"\nimport { isCSSVariableName } from \"../../../animation/utils/is-css-variable\"\nimport { ResolvedValues } from \"../../types\"\nimport { HTMLRenderState } from \"../types\"\nimport { buildTransform } from \"./build-transform\"\nimport type { MotionNodeOptions } from \"../../../node/types\"\n\nexport function buildHTMLStyles(\n    state: HTMLRenderState,\n    latestValues: ResolvedValues,\n    transformTemplate?: MotionNodeOptions[\"transformTemplate\"]\n) {\n    const { style, vars, transformOrigin } = state\n\n    // Track whether we encounter any transform or transformOrigin values.\n    let hasTransform = false\n    let hasTransformOrigin = false\n\n    /**\n     * Loop over all our latest animated values and decide whether to handle them\n     * as a style or CSS variable.\n     *\n     * Transforms and transform origins are kept separately for further processing.\n     */\n    for (const key in latestValues) {\n        const value = latestValues[key]\n\n        if (transformProps.has(key)) {\n            // If this is a transform, flag to enable further transform processing\n            hasTransform = true\n            continue\n        } else if (isCSSVariableName(key)) {\n            vars[key] = value\n            continue\n        } else {\n            // Convert the value to its default value type, ie 0 -> \"0px\"\n            const valueAsType = getValueAsType(value, numberValueTypes[key])\n\n            if (key.startsWith(\"origin\")) {\n                // If this is a transform origin, flag and enable further transform-origin processing\n                hasTransformOrigin = true\n                transformOrigin[key as keyof typeof transformOrigin] =\n                    valueAsType\n            } else {\n                style[key] = valueAsType\n            }\n        }\n    }\n\n    if (!latestValues.transform) {\n        if (hasTransform || transformTemplate) {\n            style.transform = buildTransform(\n                latestValues,\n                state.transform,\n                transformTemplate\n            )\n        } else if (style.transform) {\n            /**\n             * If we have previously created a transform but currently don't have any,\n             * reset transform style to none.\n             */\n            style.transform = \"none\"\n        }\n    }\n\n    /**\n     * Build a transformOrigin style. Uses the same defaults as the browser for\n     * undefined origins.\n     */\n    if (hasTransformOrigin) {\n        const {\n            originX = \"50%\",\n            originY = \"50%\",\n            originZ = 0,\n        } = transformOrigin\n        style.transformOrigin = `${originX} ${originY} ${originZ}`\n    }\n}\n","import type { MotionStyle } from \"../../VisualElement\"\nimport { HTMLRenderState } from \"../types\"\n\nexport function renderHTML(\n    element: HTMLElement,\n    { style, vars }: HTMLRenderState,\n    styleProp?: MotionStyle,\n    projection?: any\n) {\n    const elementStyle = element.style\n\n    let key: string\n    for (key in style) {\n        // CSSStyleDeclaration has [index: number]: string; in the types, so we use that as key type.\n        elementStyle[key as unknown as number] = style[key] as string\n    }\n\n    // Write projection styles directly to element style\n    projection?.applyProjectionStyles(elementStyle, styleProp)\n\n    for (key in vars) {\n        // Loop over any CSS variables and assign those.\n        // They can only be assigned using `setProperty`.\n        elementStyle.setProperty(key, vars[key] as string)\n    }\n}\n","import { px } from \"../../value/types/numbers/units\"\nimport type { Axis } from \"motion-utils\"\nimport type { ScaleCorrectorDefinition } from \"./types\"\n\nexport function pixelsToPercent(pixels: number, axis: Axis): number {\n    if (axis.max === axis.min) return 0\n    return (pixels / (axis.max - axis.min)) * 100\n}\n\n/**\n * We always correct borderRadius as a percentage rather than pixels to reduce paints.\n * For example, if you are projecting a box that is 100px wide with a 10px borderRadius\n * into a box that is 200px wide with a 20px borderRadius, that is actually a 10%\n * borderRadius in both states. If we animate between the two in pixels that will trigger\n * a paint each time. If we animate between the two in percentage we'll avoid a paint.\n */\nexport const correctBorderRadius: ScaleCorrectorDefinition = {\n    correct: (latest, node) => {\n        if (!node.target) return latest\n\n        /**\n         * If latest is a string, if it's a percentage we can return immediately as it's\n         * going to be stretched appropriately. Otherwise, if it's a pixel, convert it to a number.\n         */\n        if (typeof latest === \"string\") {\n            if (px.test(latest)) {\n                latest = parseFloat(latest)\n            } else {\n                return latest\n            }\n        }\n\n        /**\n         * If latest is a number, it's a pixel value. We use the current viewportBox to calculate that\n         * pixel value as a percentage of each axis\n         */\n        const x = pixelsToPercent(latest, node.target.x)\n        const y = pixelsToPercent(latest, node.target.y)\n\n        return `${x}% ${y}%`\n    },\n}\n","import { complex } from \"../../value/types/complex\"\nimport { mixNumber } from \"../../utils/mix/number\"\nimport type { ScaleCorrectorDefinition } from \"./types\"\n\nexport const correctBoxShadow: ScaleCorrectorDefinition = {\n    correct: (latest: string, { treeScale, projectionDelta }) => {\n        const original = latest\n        const shadow = complex.parse(latest)\n\n        // TODO: Doesn't support multiple shadows\n        if (shadow.length > 5) return original\n\n        const template = complex.createTransformer(latest)\n        const offset = typeof shadow[0] !== \"number\" ? 1 : 0\n\n        // Calculate the overall context scale\n        const xScale = projectionDelta!.x.scale * treeScale!.x\n        const yScale = projectionDelta!.y.scale * treeScale!.y\n\n        // Scale x/y\n        ;(shadow[0 + offset] as number) /= xScale\n        ;(shadow[1 + offset] as number) /= yScale\n\n        /**\n         * Ideally we'd correct x and y scales individually, but because blur and\n         * spread apply to both we have to take a scale average and apply that instead.\n         * We could potentially improve the outcome of this by incorporating the ratio between\n         * the two scales.\n         */\n        const averageScale = mixNumber(xScale, yScale, 0.5)\n\n        // Blur\n        if (typeof shadow[2 + offset] === \"number\")\n            (shadow[2 + offset] as number) /= averageScale\n\n        // Spread\n        if (typeof shadow[3 + offset] === \"number\")\n            (shadow[3 + offset] as number) /= averageScale\n\n        return template(shadow)\n    },\n}\n","import { isCSSVariableName } from \"../../animation/utils/is-css-variable\"\nimport { cornerRadiusProps } from \"../../utils/border-radius\"\nimport { correctBorderRadius } from \"./scale-border-radius\"\nimport { correctBoxShadow } from \"./scale-box-shadow\"\nimport type { ScaleCorrectorMap } from \"./types\"\n\nexport const scaleCorrectors: ScaleCorrectorMap = {\n    borderRadius: {\n        ...correctBorderRadius,\n        applyTo: [...cornerRadiusProps],\n    },\n    borderTopLeftRadius: correctBorderRadius,\n    borderTopRightRadius: correctBorderRadius,\n    borderBottomLeftRadius: correctBorderRadius,\n    borderBottomRightRadius: correctBorderRadius,\n    boxShadow: correctBoxShadow,\n}\n\nexport function addScaleCorrector(correctors: ScaleCorrectorMap) {\n    for (const key in correctors) {\n        scaleCorrectors[key] = correctors[key]\n        if (isCSSVariableName(key)) {\n            scaleCorrectors[key].isCSSVariable = true\n        }\n    }\n}\n","import { transformProps } from \"./keys-transform\"\nimport type { MotionNodeOptions } from \"../../node/types\"\nimport {\n    scaleCorrectors,\n    addScaleCorrector,\n} from \"../../projection/styles/scale-correction\"\n\nexport { scaleCorrectors, addScaleCorrector }\n\nexport function isForcedMotionValue(\n    key: string,\n    { layout, layoutId }: MotionNodeOptions\n) {\n    return (\n        transformProps.has(key) ||\n        key.startsWith(\"origin\") ||\n        ((layout || layoutId !== undefined) &&\n            (!!scaleCorrectors[key] || key === \"opacity\"))\n    )\n}\n","import { isMotionValue } from \"../../../value/utils/is-motion-value\"\nimport type { MotionNodeOptions } from \"../../../node/types\"\nimport { isForcedMotionValue } from \"../../utils/is-forced-motion-value\"\nimport type { VisualElement } from \"../../VisualElement\"\n\nexport function scrapeMotionValuesFromProps(\n    props: MotionNodeOptions,\n    prevProps: MotionNodeOptions,\n    visualElement?: VisualElement\n) {\n    const style = (props as any).style\n    const prevStyle = (prevProps as any)?.style\n    const newValues: { [key: string]: any } = {}\n\n    if (!style) return newValues\n\n    for (const key in style) {\n        if (\n            isMotionValue(style[key]) ||\n            (prevStyle && isMotionValue(prevStyle[key])) ||\n            isForcedMotionValue(key, props) ||\n            visualElement?.getValue(key)?.liveStyle !== undefined\n        ) {\n            newValues[key] = style[key]\n        }\n    }\n\n    return newValues\n}\n","import type { Box } from \"motion-utils\"\nimport type { AnyResolvedKeyframe } from \"../../animation/types\"\nimport { isCSSVariableName } from \"../../animation/utils/is-css-variable\"\nimport type { MotionNodeOptions } from \"../../node/types\"\nimport { transformProps } from \"../utils/keys-transform\"\nimport {\n    defaultTransformValue,\n    readTransformValue,\n} from \"../dom/parse-transform\"\nimport { measureViewportBox } from \"../../projection/utils/measure\"\nimport { DOMVisualElement } from \"../dom/DOMVisualElement\"\nimport type { DOMVisualElementOptions } from \"../dom/types\"\nimport type { ResolvedValues, MotionConfigContextProps } from \"../types\"\nimport type { VisualElement } from \"../VisualElement\"\nimport { HTMLRenderState } from \"./types\"\nimport { buildHTMLStyles } from \"./utils/build-styles\"\nimport { renderHTML } from \"./utils/render\"\nimport { scrapeMotionValuesFromProps } from \"./utils/scrape-motion-values\"\n\nexport function getComputedStyle(element: HTMLElement) {\n    return window.getComputedStyle(element)\n}\n\nexport class HTMLVisualElement extends DOMVisualElement<\n    HTMLElement,\n    HTMLRenderState,\n    DOMVisualElementOptions\n> {\n    type = \"html\"\n\n    readValueFromInstance(\n        instance: HTMLElement,\n        key: string\n    ): AnyResolvedKeyframe | null | undefined {\n        if (transformProps.has(key)) {\n            return this.projection?.isProjecting\n                ? defaultTransformValue(key)\n                : readTransformValue(instance, key)\n        } else {\n            const computedStyle = getComputedStyle(instance)\n            const value =\n                (isCSSVariableName(key)\n                    ? computedStyle.getPropertyValue(key)\n                    : computedStyle[key as keyof typeof computedStyle]) || 0\n\n            return typeof value === \"string\" ? value.trim() : (value as number)\n        }\n    }\n\n    measureInstanceViewportBox(\n        instance: HTMLElement,\n        { transformPagePoint }: MotionNodeOptions & Partial<MotionConfigContextProps>\n    ): Box {\n        return measureViewportBox(instance, transformPagePoint)\n    }\n\n    build(\n        renderState: HTMLRenderState,\n        latestValues: ResolvedValues,\n        props: MotionNodeOptions\n    ) {\n        buildHTMLStyles(renderState, latestValues, props.transformTemplate)\n    }\n\n    scrapeMotionValuesFromProps(\n        props: MotionNodeOptions,\n        prevProps: MotionNodeOptions,\n        visualElement: VisualElement\n    ) {\n        return scrapeMotionValuesFromProps(props, prevProps, visualElement)\n    }\n\n    renderInstance = renderHTML\n}\n","import { createBox } from \"../../projection/geometry/models\"\nimport { ResolvedValues } from \"../types\"\nimport { VisualElement } from \"../VisualElement\"\n\ninterface ObjectRenderState {\n    output: ResolvedValues\n}\n\nfunction isObjectKey(key: string, object: Object): key is keyof Object {\n    return key in object\n}\n\nexport class ObjectVisualElement extends VisualElement<\n    Object,\n    ObjectRenderState\n> {\n    type = \"object\"\n\n    readValueFromInstance(instance: Object, key: string) {\n        if (isObjectKey(key, instance)) {\n            const value = instance[key]\n            if (typeof value === \"string\" || typeof value === \"number\") {\n                return value\n            }\n        }\n\n        return undefined\n    }\n\n    getBaseTargetFromProps() {\n        return undefined\n    }\n\n    removeValueFromRenderState(\n        key: string,\n        renderState: ObjectRenderState\n    ): void {\n        delete renderState.output[key]\n    }\n\n    measureInstanceViewportBox() {\n        return createBox()\n    }\n\n    build(renderState: ObjectRenderState, latestValues: ResolvedValues) {\n        Object.assign(renderState.output, latestValues)\n    }\n\n    renderInstance(instance: Object, { output }: ObjectRenderState) {\n        Object.assign(instance, output)\n    }\n\n    sortInstanceNodePosition() {\n        return 0\n    }\n}\n","import { ResolvedValues } from \"../../types\"\n\nconst dashKeys = {\n    offset: \"stroke-dashoffset\",\n    array: \"stroke-dasharray\",\n}\n\nconst camelKeys = {\n    offset: \"strokeDashoffset\",\n    array: \"strokeDasharray\",\n}\n\n/**\n * Build SVG path properties. Uses the path's measured length to convert\n * our custom pathLength, pathSpacing and pathOffset into stroke-dashoffset\n * and stroke-dasharray attributes.\n *\n * This function is mutative to reduce per-frame GC.\n *\n * Note: We use unitless values for stroke-dasharray and stroke-dashoffset\n * because Safari incorrectly scales px values when the page is zoomed.\n */\nexport function buildSVGPath(\n    attrs: ResolvedValues,\n    length: number,\n    spacing = 1,\n    offset = 0,\n    useDashCase: boolean = true\n): void {\n    // Normalise path length by setting SVG attribute pathLength to 1\n    attrs.pathLength = 1\n\n    // We use dash case when setting attributes directly to the DOM node and camel case\n    // when defining props on a React component.\n    const keys = useDashCase ? dashKeys : camelKeys\n\n    // Build the dash offset (unitless to avoid Safari zoom bug)\n    attrs[keys.offset] = `${-offset}`\n\n    // Build the dash array (unitless to avoid Safari zoom bug)\n    attrs[keys.array] = `${length} ${spacing}`\n}\n","import type { MotionNodeOptions } from \"../../../node/types\"\nimport { buildHTMLStyles } from \"../../html/utils/build-styles\"\nimport { ResolvedValues } from \"../../types\"\nimport { SVGRenderState } from \"../types\"\nimport { buildSVGPath } from \"./path\"\n\n/**\n * CSS Motion Path properties that should remain as CSS styles on SVG elements.\n */\nconst cssMotionPathProperties = [\n    \"offsetDistance\",\n    \"offsetPath\",\n    \"offsetRotate\",\n    \"offsetAnchor\",\n]\n\n/**\n * Build SVG visual attributes, like cx and style.transform\n */\nexport function buildSVGAttrs(\n    state: SVGRenderState,\n    {\n        attrX,\n        attrY,\n        attrScale,\n        pathLength,\n        pathSpacing = 1,\n        pathOffset = 0,\n        // This is object creation, which we try to avoid per-frame.\n        ...latest\n    }: ResolvedValues,\n    isSVGTag: boolean,\n    transformTemplate?: MotionNodeOptions[\"transformTemplate\"],\n    styleProp?: Record<string, any>\n) {\n    buildHTMLStyles(state, latest, transformTemplate)\n\n    /**\n     * For svg tags we just want to make sure viewBox is animatable and treat all the styles\n     * as normal HTML tags.\n     */\n    if (isSVGTag) {\n        if (state.style.viewBox) {\n            state.attrs.viewBox = state.style.viewBox\n        }\n        return\n    }\n\n    state.attrs = state.style\n    state.style = {}\n    const { attrs, style } = state\n\n    /**\n     * However, we apply transforms as CSS transforms.\n     * So if we detect a transform, transformOrigin we take it from attrs and copy it into style.\n     */\n    if (attrs.transform) {\n        style.transform = attrs.transform\n        delete attrs.transform\n    }\n    if (style.transform || attrs.transformOrigin) {\n        style.transformOrigin = attrs.transformOrigin ?? \"50% 50%\"\n        delete attrs.transformOrigin\n    }\n\n    if (style.transform) {\n        /**\n         * SVG's element transform-origin